INSERT INTO categories VALUES(6,'data-lists','Dynamic Lists','Data Lists functions',NULL,0,'','2025-12-03 03:54:56');
INSERT INTO entries VALUES(1,'dlp_addErrData','command',1,'dlp_addErrData','Add error bar data to a plot','This function is used to add data to a graph plot which can later be used to specify sizes for error bars with the dlp_addErrbarCmd command.  It returns a number which may be given to dlp_addErrCmd to refer to the data set given.','dlp','dlp_addErrData `plot data`','Data set number which can be used to reference the data added','dlp_addErrbarCmd, dlp_addXDataanddlp_addYData, dlp_addErrbars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:55','2025-12-03 03:54:55');
INSERT INTO entries VALUES(2,'dlp_pushpanel','command',1,'dlp_pushpanel','Saves the current view port and selects a `panel`for output','The function dlp_pushpanel is useful for displaying several graphs simultaneously.  Note that the dlp_subplot function is normally adequate for this purpose, so you should rarely if ever have to use this function directly.  It treats the view port as being divided into a grid of `panels`, the dimensions of which may be chosen using the function dlp_setpanels, numbered in order from left to right and from top to bottom (so that in a six by five grid the first panel of the top row would be number nought, the second number one, the last number five and the first of the second row number six).  Calling dlp_pushpanel saves information needed to restore the current screen view port and then readjusts the view port to fit in with the panel numbered `id`.  If dlp_pushpanel is called twice, a `panel within a panel` will be selected.  The view port information saved may be restored using the command dlp_poppanel.  The information is saved using a `stack` scheme: calling dlp_poppanel will restore the information saved by the most recent call to dlp_pushpanel.  The saved information will then be forgotten, and the next call to dlp_poppanel will restore the next most recent set of information, and so on.  The example will attempt to illustrate this idea.  The `stack` of saved information is the same as is used by dlp_pushwindow, so you should be careful when mixing calls to these two functions (you should not normally need to do this anyway).','dlp','dlp_pushpanel `id`','','dlp_poppanel, dlp_subplot, dlp_setpanels, dlp_popwindow','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(3,'dlp_getaspect','command',1,'dlp_getaspect','Returns the width to height ratio for a graph plot','This function calculates the ratio of width to height of the view port for the graph plot `plot`, where width and height are in percentage of the window size.  This can be useful for plots which contain aspect-dependent elements, but which are not overall aspect dependent.  One might insert a command via dlp_cmd to adjust the graphics output accordingly.  For plots which depend entirely on the aspect being correct, one may also tell %%\%%dlsh%%\%% to force an aspect ratio of one, using the command *`dlp_set plot`* `adjustxy 1`.','dlp','dlp_getaspect `plot`','The aspect ratio','dlp_cmd','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(4,'dlp_copy','command',1,'dlp_copy','Duplicates a graph plot structure','This function creates replica of the graph plot `plot`.  The replica will be given the name `newname`.  If a graph of that name already exists, it will be erased beforehand.  One use of dlp_copy is to speed up the creation of two similar graphs: the first graph is created, all parameters which are identical for both graphs are set, then the graph is reproduced using dlp_copy, and the remaining parameters are set on both.','dlp','dlp_copy `plot newplot`','The name of the new graph plot created','dlp_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(5,'dlp_delete','command',1,'dlp_delete','Deletes a graph plot which is no longer needed','This function erases a graph plot, and frees any system resources which it may be using.  You should call dlp_delete for a plot with which you are finished.  An error will arise if the plot does not exist.','dlp','dlp_delete `plot`','','dlp_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(6,'dlp_pagedims','command',1,'dlp_pagedims','Changes the postscript output dimensions','Changes the postscript output dimensions','dlp','dlp_pagedims `x y`','','dlp_landscape, dlp_portrait','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(7,'dlp_plot','command',1,'dlp_plot','Plots a graph onto the display','dlp_plot draws a graph plot onto the default graphics device of %%\%%dlsh.  This can mean drawing it into an X or Windows window, or into an off-screen buffer which can be saved to a file.  Since graph plots are saved as a collection of data and TCL commands to display the data, which are only carried out after a dlp_plot command, it is possible that errors may appear at this stage from former commands which appeared to succeed at the time when they were entered.','dlp','dlp_plot `plot`','Name of the plot drawn','dlp_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(8,'dlp_addErrbars','command',1,'dlp_addErrbars','Add error bars to a plot with the sizes supplied',replace('This command adds error bars to the graph plot *plot*, at the\nco-ordinates given by *dataset*.  *dataset* must be either\none or two numbers, referring to co-ordinate sets previously given to\ndlp_addXData and dlp_addYData.  If two numbers are given, they refer\nto a set of x and of y co-ordinate data respectively.  A single\nnumber is taken to refer to a set of y data; in this case, the first\nset of x data entered will be used.  The error bars are drawn as a\nline (using dlg_lines) joining two markers (dlg_markers).  The size\nof the bars at the various points is given by the list *\nerrdata*.  The following extra arguments may be passed to control\nthe way in which the bars are drawn:\n\n\n**-margs `args`*: extra arguments to pass to dlg_markers\n**-largs `args`*: extra arguments to pass to dlg_lines\n**-vert*: the error bars should be drawn vertically, as bydefault\n**-up*: only the top half of the bars should be drawn\n**-down*: only the bottom half should be drawn\n**-horiz*: the error bars should be drawn horizontally\n**left*: only the left half of the bars should be drawn\n**right*: only the right half should be drawn\n**offset `value`*: the bars should be offset horizontallyby `value`, which may be a single number or a list','\n',char(10)),'dlp','dlp_addErrbars `plot dataset errdata [args]`','The name of the dynamic list storing the commands used to draw *plot*','dlp_addErrbarCmd, dlp_addErrData','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(9,'dlp_setpanels','command',1,'dlp_setpanels','Configures view port `panels` for displaying several graphs','dlp_setpanels controls the dividing up of the view port into a grid of `panels` into which plots can be drawn.  In order to display a three by two table of graphs, one would first divide up the view port using *dlp_setpanels 2 3* and then plot the various graphs into the various panels using dlp_subplot with the plot name and the panel number.  The panels are numbered from left to right, top to bottom, so that the first panel in the first row is number nought, the second number one, the third number two, then the first of the second row number three and so on.  Calling this function does not affect the working of dlp_plot, which will always use the full view port regard less of the way it is divided up.','dlp','dlp_setpanels `lines columns`','Number of lines and of columns allocated','dlp_getpanels, dlp_subplot, dlp_pushpanel, dlp_poppanel','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(10,'dlp_write','command',1,'dlp_write','','','dlp','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(11,'dlp_postcmd','command',1,'dlp_postcmd','Adds a post-drawing command to a graph plot','This function causes the<nowiki> \</nowiki>dlsh<nowiki>\</nowiki> command `cmd` to be executed each time the graph plot `plot` is drawn, after the drawing commands are carried out.  The command is added to a list within the plot structure, so if dlp_postcmd is called several times, all of the commands given will be carried out.  The plotting view port is saved before each command and restored afterwards.  If a plot structure is saved to disk, the command lists contained in it will be saved with it, but variables and external functions which the commands may need to work will not automatically be saved.  This function is probably most useful for cleaning up after complex operations using dlp_cmd, or for displaying information (say postscript) on top of a graph.  The variable *$hisplot* is set to the name of the graph being plotted while drawing takes place, so it may be used to reference the plot.  The elements cur_xmin, cur_ymin, cur_xmax and cur_ymax of the plot structure are set to the co-ordinates of the extreme points of the graph.  Note that none of the commands attached to a graph are actually executed until the graph is drawn, so it is possible to add an invalid command to a plot without<nowiki> \</nowiki>dlsh<nowiki>\</nowiki> complaining at the time.  Note also that the commands are saved in text form, which means that they must be read and analysed each time the graph is drawn - because of this, overuse of this command can significantly slow down plotting.','dlp','dlp_postcmd `plot cmd`','Dynamic list of the post-drawing commands contained in `plot`','dlp_cmds','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(12,'dlp_popwindow','command',1,'dlp_popwindow','Restores the window state after a call to dlp_pushwindow','This function is similar to dlp_poppanel, but it works in conjunction with dlp_pushwindow rather than dlp_pushpanel.','dlp','dlp_popwindow','','dlp_pushwindow, dlp_poppanel, dlp_pushpanel','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(13,'dlp_portrait','command',1,'dlp_portrait','Sets the postscript page orientation to portrait','When a %%\%%dlsh%%\%% plot is converted to postscript, it is possible to save it in either portrait or landscape page orientation.  This function sets the default value to portrait.','dlp','dlp_portrait','','dlp_landscape','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(14,'dlp_pushwindow','command',1,'dlp_pushwindow','Sets up the view port for plotting a graph','This function sets up the view port for plotting a graph, and is intended to be called from the plotting pre-commands of a graph plot (which may be set using dlp_cmd).  It sets up the view port correctly for the graph `plot`, using information saved just before the pre-commands are carried out, and saves the information about how the view port was previously set up.  For information on the way the information is saved and restored, see the entry on dlp_pushpanel.  This function should be followed at some point by a call to dlp_popwindow.','dlp','dlp_pushwindow `plot`','','dlp_popwindow, dlp_pushpanel, dlp_poppanel','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(15,'dlp_exists','command',1,'dlp_exists','Tests whether a graph plot with a given name exists','The function dlp_exists tests whether a graph plot of the name `plot` exists. It returns 1 if this is the case, and 0 otherwise.  This can be used as an error test in functions which take a plot name as an argument.','dlp','dlp_exists `plot`','1 if the plot exists, 0 otherwise','dlp_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(16,'dlp_clean','command',1,'dlp_clean','Deletes temporary graph plots','When a new plot is created within %%\%%dlsh%%\%% without a name being given to it, it is assigned a name such as plot0 or plot2.  Plots with such names are considered to be temporary, since there is usually no way of accessing them later.  The dlg_clean function will delete any temporary plots which exist at the time it is called, freeing any system resources which they are taking up.','dlp','dlp_clean','','dlp_newplot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(17,'dlp_bars','command',1,'dlp_bars','Add bars to a graph',replace('The bars mode of the dlp_draw function plots a bar chart based on the point information given in `dataset`.  ` dataset` is either a single number, that of a set of y co-ordinate data previously returned by dlp_addYData, or two numbers - one a set of x and one of y co-ordinate data.  If no x data is given, the first set entered with dlp_addXData is used.  If no extra arguments are given, hollow bars will be drawn between the x axis and the points specified.  You may change the way they are drawn by putting the following arguments int the `args` parameter:\n\n\n* *-lstyle `style` *: sets the outline drawing style usedfrom solid (1) to sparse dashes(6).\n* *-lwidth `width` *: sets the width of the outline\n* *-linecolor `colour` *: causes the outlines to be drawnusing the `colour`  specified.\n* *-filled `bool` *: a non-zero value causes the bars tobe drawn filled in with the default colour (see *setcolor*)\n* *-fillcolor `colour` *: causes the bars to be filled inusing `colour`.\n* *-interbar `spacing` *: sets the interbar spacing,which is used for width and offset calculation; by default, this isset to the space between the first and second bars.\n* *-width `width` *: draws the bars with the given `width`, as a proportion of the interbar spacing.\n* *-offset `value` *: causes the bars to be drawn offsetby a proportion of `value`  of the interbar; can be useful fordrawing double bar charts.','\n',char(10)),'dlp',replace('dlp_draw `plot` bars \\  dataset `[args]`\n\n\ndlp_bars `plot args`','\n',char(10)),'','dlp_draw, dlp_lines, dlp_disjointLines, dlp_markers, dlp_text, dlp_steps','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(18,'dlp_read','command',1,'dlp_read','Read a previously saved graph plot from a file','The dlp_read function is used to read plot information which was saved using dlp_write.  All plotting information and commands may be restored in this way, and any data which was attached to the plot using dlp_set; however any other data, and any external procedures on which the plot relies must be looked after separately.  If a `name` is not supplied, the plot read will have the same name as before it was saved.  If a plot of that name already exists, it will be overwritten.','dlp','dlp_read `file [name]`','Name of the plot read','dlp_write','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(19,'dlp_reset','command',1,'dlp_reset','Resets parameters in a graph plot','This function deletes the contents of elements in a graph plot.  The plot to be modified is specified with the `plot` argument, while the `Paramus` argument contains the names of the elements to be reset.  One use for this function is to create a new graph from an existing one by deleting and adding afresh small amounts of data within the graph.  It can also be useful for correcting errors made when producing a graph on the fly, although it is recommended, when creating a graph containing any sizeable amount of information, to use a script file for the purpose.','dlp','dlp_reset `plot Paramus`','','dlp_set','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(20,'dlp_draw','command',1,'dlp_draw','Display the points in a graph','dlp_draw is the %%\%%dlsh%%\%% plot function which actually takes care of displaying graphs.  It requires sets of co-ordinates to have been entered using dlp_addXData and dlp_addYData (it is always possible to enter the data after the call to dlp_draw, but before the graph is displayed).  The argument `dataset` specifies the sets of X and Y co-ordinate data to use.  If a single number is given, it is taken to mean the set of Y data which should be used, and X dataset 0 is used.  If `dataset` is a list of two numbers, the first is taken to be the X dataset and the second the Y.  By default, function can be one of *bars*, *lines*, *disjointLines*, *markers*, *steps* or *text*.  For a description of the arguments which may be passed in `args`, see the descriptions of dlp_bars, dlp_lines etc.%%\%%par It is possible to add your own drawing functions to dlp_draw.  To do so, you must add a function with a name of the form dlp_` func`, which will be available as the dlp_draw function `func`.  It will then be called by dlp_draw when the graph is plotted with the arguments `plot xlist ylist args…` where `plot` is the graph plot used, `xlist` and `ylist` respectively the X and Y co-ordinates of the points to be drawn, and `args` any further arguments passed to dlp_draw.  The %%\%%dlsh%%\%% graphic window is set up correctly for the plot; you should call dlp_pushwindow `plot` at the beginning, and dlp_popwindow at the end of your procedure to preserve this information.','dlp','dlp_draw `plot function dataset args`','Current list of plotting commands for the graph `plot`','dlp_addXDataanddlp_addYData','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(21,'dlp_xyplot','command',1,'dlp_xyplot','Create a line graph of a set of data','dlp_xyplot is a routine to quickly create a line graph for a set of data.  It takes as arguments a set of X co-ordinate data, a set of Y co-ordinate data and an optional set of error data.  It creates a graph structure based on this information which consists of a set of lines connecting the points given by the co-ordinate data.  It also adds square markers at the positions of the points, as well as vertical error bars if error data is supplied.','dlp','dlp_xyplot `xdata ydata [errdata]`','Name of newly created plot','dlp_barchart, dlp_create, dlp_emptyplot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(22,'dlp_landscape','command',1,'dlp_landscape','Sets the postscript page orientation to landscape','When a graph plot created by %%\%%dlsh%%\%% is converted to postscript format, it is possible to convert with either portrait or landscape page orientation.  dlp_landscape sets the page orientation to landscape mode.','dlp','dlp_landscape','','dlp_portrait','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(23,'dlp_winpostscriptAt','command',1,'dlp_winpostscriptAt','','','dlp','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(24,'dlp_subplot','command',1,'dlp_subplot','Plots a graph into a `panel` of the display','dlp_plot draws a graph plot into a `panel` of the default graphics device of %%\%%dlsh.  The `view port` of the device is divided for this purpose into a number of rows and columns (which may be chosen using the command dlp_setpanels) of panels.  These are numbered from left to right and from top to bottom, so that the top left panel is number zero, the second on the top row number one, and so on, with the first of the second row following in number the last of the first row.%%\%%par Graph plots in %%\%%dlsh%%\%% are saved as a collection of data and TCL commands to manipulate and display that data.  These are stored within the graph as they are given, and will not actually be examined until dlp_plot or dlp_subplot is called to carry them out.  Because of this, many errors which may be traced back to the creation of the graph will only appear at this point.  This concerns in particular commands explicitly entered using dlp_cmd and dlp_postcmd.','dlp','dlp_subplot `plot panel`','The name of the plot shown','dlp_plot, dlp_setpanels, dlp_getpanels, dlp_pushpanels, dlp_poppanels','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(25,'dlp_newplot','command',1,'dlp_newplot','Creates a new graph plot structure','dlp_newplot creates a new graph plot structure ready to be drawn upon.  The axes of the graph will be scaled by default to fit data subsequently plotted onto it.  The graph returns its name, which will be of the form plot`x`.  Unless it is renamed, it will be treated as a temporary graph, and will be deleted if dlp_clean is called.','dlp','dlp_newplot','The name of the new graph plot','dlp_create, dlp_rename, dlp_clean','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(26,'dlp_wingetaspect','command',1,'dlp_wingetaspect','Gives the width to height ratio of a graph''s view port within a window','This function returns the width to height aspect ratio which the view port belonging to the graph `plot` would have inside of the specified window frame.  The window is specified through its co-ordinates: minimum X, minimum Y, maximum X and maximum Y.','dlp','dlp_wingetaspect `plot window`','The aspect ratio','dlp_getaspect','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(27,'dlp_poppanel','command',1,'dlp_poppanel','Restores the view port after a call to dlp_pushpanel','dlp_poppanel restores the graphics view port after a call to dlp_pushpanel.  This means that any graphics or plotting operations carried out after a call to this function will act as though the last call to dlp_pushpanel, as well as any later operations on the view port, had never taken place.  This extends itself to dlp_poppanel itself: if it is called twice, it will restore the view port to the state which it was in before the last call but one to dlp_pushpanel.  If dlp_poppanel is called more often than dlp_pushpanel, an error will arise.  Note that dlp_poppanel is really identical to dlp_popwindow, so calling dlp_pushwindow and then dlp_poppanel is allowed, although not recommended.','dlp','dlp_poppanel','','dlp_pushpanel, dlp_popwindow, dlp_pushwindow','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(28,'dlp_addXData, dlp_addYData','command',1,'dlp_addXData, dlp_addYData','Adds a set of point co-ordinates to a graph plot',replace('The dlp_addXData and dlp_addYData functions are used for adding\npoint co-ordinates to a \dlsh\ graph plot.  To plot to a graph, you\nmust call these functions to supply the data for the point\nco-ordinates, giving as arguments the graph plot which you wish to\nmodify and the co-ordinates (x co-ordinates in the call to\ndlp_addXData, y in that to dlp_addYData) at which you wish to plot\nas a dynamic list, and then use other functions such as dlp_draw to\ntell \dlsh\ how you wish the graph to be drawn.  These functions\nreturn a number which references the list of co-ordinates added, and\nwhich you must pass on to functions which make use if the co-ordinate\ndata.  It is worth noting that the number returned is always one\ngreater than the previous (X and Y co-ordinate data are kept track\nof separately), and that the first set of X Data entered (set 0) is\nused as a default by many functions.','\n',char(10)),'dlp',replace('dlp_addXData `plot data`\ndlp_addYData `plot data`','\n',char(10)),'Data set number which can be used to reference the data added','dlp_create, dlp_draw, dlp_plot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(29,'dlp_emptyplot','command',1,'dlp_emptyplot','Create a plot but turn off all visual elements','dlp_emptyplot is used to create a plot canvas for drawing onto.  All normal plot functions work the new plot, although no visual elements are displayed by default.  It provides a convenient way to create a graphics object that contains graphics commands.  Because the plot can be drawn inside any arbitrary view port it is scalable.  The default window for the empty plot is 0 to 10 in both the x and y directions. This can be changed, as with any plot, using either the dlp_setxrange and dlp_setyrange functions or by setting the min and max values using dlp_set.','dlp','dlp_emptyplot','Name of the newly created plot','dlp_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(30,'dlp_reset data','command',1,'dlp_reset data','Deletes plotting data contained in a graph','This function resets all data in a graph used for plotting.  This means all co-ordinate data, all error bar data and all plotting commands (although not pre- and post-plotting commands).  Additional parameters such as plot title and labels are not touched.','dlp','dlp_reset data `plot`','Empty list of plotting commands for `plot`','dlp_reset, dlp_set','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(31,'dlp_barchart','command',1,'dlp_barchart','Create a basic bar chart plot which can then be modified','dlp_barchart is useful for quickly creating simple bar charts.  It creates a new graph plot, to which it adds error bars at the positions specified by `xplaces`, with the heights specified by `ydata` and optionally with error bars of the magnitudes specified by `errdata`.  It returns the name of the plot created.  Note that the x, y and error data sets supplied will automatically be added to the plot just after it is created using dlg_addXData, dlg_addYData and dlg_addErrData respectively.','dlp','dlp_barchart `xplaces ydata [errdata]`','Name of newly created plot','dlp_create, dlp_draw','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(32,'dlp_addErrbarCmd','command',1,'dlp_addErrbarCmd','Plots error bars, based on previously entered error sizes','dlp_addErrbarCmd is identical to dlp_addErrbars except that where dlp_addErrbars takes as its argument a set of data, this command takes the number of a set of data which was previously added using the dlp_addErrData command.','dlp','dlp_addErrbarCmd `plot dataset errset [args]`','The name of the dynamic list storing the commands used to draw *plot*','dlp_addErrData, dlp_addErrbars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(33,'dlp_winpostcmd','command',1,'dlp_winpostcmd','Adds a post-plotting command with a given window setup to a graph','Adds a post-plotting command with a given window setup to a graph','dlp','dlp_winpostcmd `plot window cmd`','List of post-plotting commands in the graph structure','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(34,'dlp_wincmd','command',1,'dlp_wincmd','Adds a pre-drawing command to a graph, setting up the window beforehand','This function is similar to dlp_cmd.  Its main difference is that the graphics window co-ordinate system will be set up to reflect the values in `window`, which is a list of the minimum X, minimum Y, maximum X and maximum Y co-ordinates to be used.  The window will be restored to its former state as soon as the command has executed.  This command is best suited to adding commands to a plot which need to be adjusted to its size, rather than its scale.  A possible use for this might be creating a graph with a background for presentational purposes.','dlp','dlp_wincmd `plot window cmd`','List of pre-plotting commands for the given graph structure','dlp_cmd, dlp_winpostcmd, dlp_postcmd','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(35,'dlp_newplotname','command',1,'dlp_newplotname','Supplies a name for a temporary graph plot','dlp_newplotname returns a name which may be given to a plot using dlp_rename.  The name corresponds to a temporary plot, and any graph plot to which it is assigned will be treated as temporary and deleted if dlp_clean is called.  There should be no need to call this function directly.','dlp','dlp_newname','A temporary name for a graph plot','dlp_create, dlp_rename, dlp_newplot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(36,'dlp_cmd','command',1,'dlp_cmd','Adds a drawing command to a graph plot','This function causes the %%\%%dlsh%%\%% command `cmd` to be executed each time the graph plot `plot` is drawn, before the drawing commands are carried out.  The command is added to a list within the plot structure, so if dlp_cmd is called several times, all of the commands given will be carried out.  The view port is not saved, so any changes made will be reflected when the graph is plotted.  If a plot structure is saved to disk, the command lists contained in it will be saved with it, but variables and external functions which the commands may need to work will not automatically be saved.  This function is probably most useful when creating graphs of data which changes over time, when it can be used for automatically processing the data to be displayed each time the graph is redrawn.  The variable *$hisplot* is set to the name of the graph being plotted while drawing takes place, so it may be used to reference the plot.  Also, the members cur_xmin, cur_ymin, cur_xmax and cur_ymax of the plot structure are set to the co-ordinates of the extremes of the graph.  Note that none of the commands attached to a graph are actually executed until the time when the graph is drawn, so it is possible to add an invalid command to a plot without %%\%%dlsh%%\%% complaining at the time.  Note also that the commands are saved in text form, which means that they must be read and analysed each time the graph is drawn - because of this, overuse of this command can significantly slow down plotting.','dlp','dlp_cmd `plot cmd`','Dynamic list containing the commands used to plot `plot`','dlp_wincmds, dlp_postcmds, dlp_winpostcmds','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(37,'dlp_pop','command',1,'dlp_pop','Pop any existing pushed view ports and temporary lists','dlp_pop is a utility function generally used to clean up after an aborted	dlp_plot.  It calls popviewport all; dlp_popTemps, and if anyarg is supplied, it also calls clearwin.','dlp','dlp_pop [all]','none','dlp_popTemps, dlp_popviewport','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(38,'dlp_create','command',1,'dlp_create','Creates a new graph plot structure or updates an old one','If no value, or a value of zero is given for the option `update`, dlp_create will create an new graph plot of the name `name`, destroying any plot of that name which might already exist.  The plot will contain axes which are by default adjusted to fit the data added.  If the function is called with a non-zero value of `update`, and a plot called `name` exists, dlp_create will look through the plot data, and add any necessary information which may be missing.  The last is mainly useful for plots which have been created with previous versions of %%\%%dlsh%%\%% and saved to disk using dlp_write.  If the plot to be updated does not exist, an error will arise.','dlp','dlp_create `name [update]`','The name of the new or updated plot','dlp_newplot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(39,'dlp_set','command',1,'dlp_set','Sets a parameter within a plot to a particular value','This function sets the entry `entry} within the graph `plot` to contain the values specified.  Any previous values which the entry may have contained are lost.  If no new values are specified, dlp_set returns the contents of `entry''''.  This command may be used for setting many plotting parameters such as title, axis labels and grid spacing which can not be configured through special purpose %%\%%dlsh%%\%% plotting commands.','dlp','dlp_set `plot entry args`','The name of the variable set, or its contents if no value is given','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(40,'dlp_getpanels','command',1,'dlp_getpanels','Returns the number of plotting panels in use','This function is useful for displaying several plots simultaneously.  The plots are laid out in a grid of `panels`; dlp_getpanels returns the number of rows and of columns in the grid as a list of integers.','dlp','dlp_getpanels','TCL integer list of rows and columns of panels','dlp_setpanels, dlp_pushpanel, dlp_poppanel, dlp_subplot','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(41,'dlp_markers','command',1,'dlp_markers','Draw markers at given points of a graph plot',replace('The markers mode of the dlp_draw function draws markers at the points given by given in `dataset`.  `dataset` is either a single number, that of a set of y co-ordinate data previously returned by dlp_addYData, or two numbers - one a set of x and one of y co-ordinate data.  If no x data is given, the first set entered with dlp_addXData is used.  If no extra arguments are given, hollow square markers will be drawn at the points specified.  You may change the way they are drawn by putting the following arguments int the `args` parameter:\n\n\n* *-marker `type` *: draw the markers in the shape `type`, where type is one of *square*   (hollow square), * fsquare* (filled square), *circle*   (hollow circle), *fcircle* (filled circle), *htick*   (horizontal bar), *htick_l* (horizontal bar stretching left), *htick_r* (horizontal bar stretching right), *vtick*   (vertical bar), * vtick_u* (vertical bar stretching up), *vtick_d*   (vertical bar stretching down) or *plus*   (crossbar).\n\n\n* *-size `size` *: draw the markers with a size of `size`.  Size is a number, which may be terminated by a letter to specify the unit used: *s*   for the current X scale, *s*   or *x*   for the current window X range, *y*   for the current window Y range and *u*   (the default) for screen points.\n* *-sizes `sizes` *: as size, but here a dynamic list of sizes must be specified (without units), one for each marker drawn.\n* *-color `colour` *: draw the markers using colour {<nowiki>\</nowiki>emcolour}.\n* *-lwidth `width` *: draw markers using lines of width`width`.\n* *-scaletype `type` *: treat the marker sizes as being of unit `type`, where type is one of the units listedpreviously.','\n',char(10)),'dlp',replace('dlp_draw `plot} markers {<nowiki>\</nowiki>em dataset [args]`\n\n\ndlp_markers `plot args`','\n',char(10)),'','dlp_draw, dlp_bars, dlp_lines, dlp_disjointLines, dlp_steps, dlp_text','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(42,'dlp_postscriptAt','command',1,'dlp_postscriptAt','Insert a postscript image into a graph plot','dlp_postscriptAt enables the rendering of postscript images within a graph.  It should be called indirectly, via dlp_cmd or dlp_postcmd, in order to make sure that the image gets rendered each time the plot is drawn.  The function must be given parameters, namely the plot name, the position at which the plot should be rendered, the name of the file containing the image to render and the width to use for the rendered image.  The plot name should be taken from the variable *$hisplot*, which is set at drawing time.  Positions and sizes are in the system of the plot, and may be calculated from the elements cur_xmin, cur_ymin, cur_xmax and cur_ymax of the plot structure, which are also set at drawing time.  It is also possible to specify a height to be used for rendering the image (by default, the height will be chosen so as to preserve the scale) and the width of lines used for rendering.  It is possible to use this command in conjunction with the dlp_emtyplot function to create a set of scalable graphics for use within %%\%%dlsh.  Note that if a graph containing postscript commands is saved to disk, then the postscript files displayed must be available when the plot is reloaded.','dlp','dlp_postscriptAt `plot x y file width [height]` [-lwidth {%%\%%em lwidth}]','','dlp_winpostscriptAt, dlp_cmd, dlp_postcmd','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(43,'dlp_lines','command',1,'dlp_lines','Draws lines between points of a graph plot',replace('The lines mode of the dlp_draw function draws a line graph based on the point information given in `dataset`.  ` dataset` is either a single number, that of a set of y co-ordinate data previously returned by dlp_addYData, or two numbers - one a set of x and one of y co-ordinate data.  If no x data is given, the first set entered with dlp_addXData is used.  If no extra arguments are given, straight lines will be drawn between the points specified.  You may change the way they are drawn by putting the following arguments int the `args` parameter:\n\n\n* *-lstyle `style` *: draw the lines in a style ranging from solid `style 1`  to sparse dashes `style 6`.\n* *-lwidth `width` *: draw lines of width `width`hundredths of a point.\n* *-linecolor `color` *: draw the lines using colour `colour`.\n* *-filled `bool` *: if a non-zero value of  `bool`  is specified, fill in the shape enclosed in the lines using the default colour.\n* *-fillcolor `color` *: fill in the shape enclosed in the lines with the colour `colour`.','\n',char(10)),'dlp',replace('dlp_draw `plot} lines {%%\%%em dataset [args]`\n\n\ndlp_lines `plot args`','\n',char(10)),'','dlp_draw, dlp_disjointLines, dlp_bars, dlp_markers, dlp_text, dlp_step','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(44,'dlp_setxrange, dlp_setyrange','command',1,'dlp_setxrange, dlp_setyrange','Specify a range for the graph axes','Generally, when a graph is plotted under %%\%%dlsh, the axes will be set up by the programme to fit in with the data within the graph.  It is however possible to specify this information manually, using the dlp_setxrange and dlp_setyrange functions, which configure the X and Y axes respectively, setting them to run between `min` and `max`.  This can be useful for example when several graphs are plotted next to each other, in order to insure that the same scale is used in each.','dlp','dlp_setxrange `plot min max` \\  dlp_setyrange `plot min max`','The plot which was changed','dlp_addXDataanddlp_addYData','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(59,'dlg_disjointLines','command',3,'dlg_disjointLines','Draw a set of disjoint lines','dlg_disjointLines draws a series of lines, which are specified in the provided dynlists.  Each line is generated by connecting the consecutive x/y pairs, but each pair is separate from the next pair.  dlg_lines, on the other hand, generates a continuous set of line segments, connected the first point to the second to the third and so on.  Options include line width **-lwidth **, specified in hundreths of a point), line color  **-linecolor** and line sytle **-lstyle**.','dlg','dlg_disjointLines xpairs ypairs [options]','None','dlg_lines','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(60,'dlg_polarlabcolor','command',3,'dlg_polarlabcolor','Specify a color using the polar L*a*b format but where a and b are repsented in C and H space. The l value sets the lightness, the c value represents chroma (0-100) and the H value is a polar angle in the range 0-360 specifying hue.',replace('Use the function to convert a desired l,c,h triplet into a desired color\nthat other *dlg_* functions can use to specify colors.  A vectorized version\nallowing many colors to be generated at once is available using *dlg_polarlabcolors*.','\n',char(10)),'dlg','dlg_polarlabcolor l c h','colorval','dlg_polarlabcolors, dlg_rgbcolor','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(61,'dlg_steps','command',3,'dlg_steps','','','dlg','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(62,'dlg_markers','command',3,'dlg_markers','','','dlg','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(63,'dlg_postscript','command',3,'dlg_postscript','','','dlg','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(64,'dlg_lines','command',3,'dlg_lines','Draws consecutive lines onto the screen','dlg_lines draws a series of lines joined end to end onto the display window.  The positions of the lines are specified by the *xlist* and *ylist* arguments which represent respectively the x and y co-ordinates for each line end point.  If these lists are not of the same length, then one of them must be a single value, in which case it will be used as a co-ordinate for every point drawn.  The function will draw a line from the first point to the second, another from the second point to the third, and so on. The way the line is drawn may be influenced by specifying options.  If the *-lwidth* option is specifyied, followed by a number, then the line will be drawn with a width of that many hundredths of a point (rounded up if necessary).  If the *-filled* option is specified, followed by the number of a fill style, and the first and last line points are the same, then the space inside of the lines will be filled in using that style. (If the lines do not join up, the effects may vary.)  The *-linecolor* and *-fillcolor* options followed by a number enable the line and filling colours respectively to be specified, while the *-lstyle* followed by a number will cause the line to be drawn with that style number. The function will fail if it is called with invalid options or point information.  The fill style and line style parameters do not appear to have any effect, but this may be system dependant.','dlg','dlg_lines xlist ylist [options]','','dlg_disjointLines, dlg_bars, dlg_steps','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(65,'dlg_text','command',3,'dlg_text','','','dlg','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(66,'dlg_image','command',3,'dlg_image','Places a bitmap image in the draw region','dlg_image','dlg','dlg_image x y imagedata scale [options]','scaled height','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(67,'dlg_rgbcolor','command',3,'dlg_rgbcolor','Convert r g b values into a single integer representation of a color used by other draw functions.',replace('Use the function to convert a desired r,g,b triplet (0-255) into a desired color\nthat other *dlg_* functions can use to specify colors.','\n',char(10)),'dlg','dlg_rgbcolor r g b','colorval','dlg_polarlabcolor','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(68,'dlg_help','command',3,'dlg_help','Prints out a summary of all dlg_ commands',replace('This function prints out a list of the names of all of the *\ndlg_* graphics functions, along with a short description of what the\nfunction does.  Most *dlg_* functions also print out a summary\nof their options if called without paramaters.','\n',char(10)),'dlg','dlg_help','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(69,'dlg_bars','command',3,'dlg_bars','Draw one or more bars (rectangles)',replace('dlg_bars draws a series of bars at the xpositions specified\nin the xlist of heights specified in the ylist (this is reversed\nif the **-sideways** option is specified).  The bars will, by\ndefault start from zero and extend to their individual values.\nAlternate starting positions can be specfied with the **-start**\noption.  The line color of the bars can be set using the\n**-linecolor** option, and the fill color with the **fillcolor** option.\nBar width is set using the **-width** option, which determines the\nwidth as a proportion of the interbar spacing.  A width of "1" means\nno space between bars, and ".5" means half of the interbar width\nis covered by the bar.  The interbar width is normally calculated\nby taking the difference between the first and second xvalue,\nhowever it can be overridden with the **-interbar** option,\nwhich specifies the distance between each bar.  This is particularly\nuseful if the xrange is not continuous.\nThe **-offset** option can be used to shift bar values along the\nthe domain, which is useful for generating "double bar" charts.\nThe offset value is, like the width argument, specified in proportion\nof interbar spacing.  To plot two sets of bars, consecutive calls\nto *dlg_bars * with different offsets, should be made.','\n',char(10)),'dlg','dlg_bars xlist ylist [options]','None','dlg_steps, dlg_lines, dlg_disjointLines','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(70,'dm_centerCols','command',4,'dm_centerCols','Centers a matrix by columns','Centers a matrix by columns','dm','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
