INSERT INTO entries VALUES(90,'dm_add','command',4,'dm_add','','','dm','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(91,'dg_asciiRead','command',5,'dg_asciiRead','Import an ASCII file as a dyngroup',replace('dg_asciiRead provides a method for importing ASCII files into\ndynamic groups.  If the *groupname* specified already exists,\nthe existing group is used (this allows multiple files to be\nconcatenated).  Note that a conflict can arise if the existing group\ncontains lists of the same name specified but which are not of the\nsame datatype.  If the group does not already exist, it is created.\nSpecified columns in the ASCII file become dynlists in the dyngroup.\nColumn specifications consist of three components: a name, a\ndatatype, and a column identifier.  The name is simply the name of a\ndynamic list, which may or may not already exist in the dyngroup.\nThe datatype is one of the primitive datatypes *int, long,\nshort, char, float, string*, excluding lists.  Numbers containing\ndecimal points cannot be read as integers, but they can be input as\nstrings, if desired.  The column id is an integer offset, specifying\na particular column to read, starting from zero.  For example, *day:int:3* would indicate that the fourth column from the left\nshould be read in as long ints and the dynlist should be called *day*.  As many column specifications as desired can be included on\nthe command line.  (The same column can even be read more than once,\npotentially as different datatypes).  If the datatype is left out\nthe column spec, *float* is assumed, and if the column id is\nomitted, the specification position is itself used as the id.\nFinally, the column specifications can be included in the ASCII\nfile, in a header line.  The header line must be the first line in\nthe ASCII file, and must begin with a *#* sign.  The rest of\nthe line can contain a list of column specifications just as if they\nwere passed on the command line.  Note that if column specifications\n`are` present on the command line, they will override a header\nline.','\n',char(10)),'dg','dg_asciiRead filename groupname [colspecs]','Name of dyngroup','dg_create, dg_append','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(92,'dg_tclListnames','command',5,'dg_tclListnames','Print out list of names of members of a dynamic group','This function prints out to the terminal the names of all member lists of a dynamic group.  It is probably most useful for debugging, since the names of the member functions should usually be known ahead of time.','dg','dg_tclListnames dyngroup','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(93,'dg_delete','command',5,'dg_delete','Delete an existing list',replace('dg_delete frees all lists associated with the group specified\nas well the group itself.  Because an error is returned if the\ngroup specified does not exist, it is often worth testing for\nthe groups existence with the dg_exist function before calling\ndg_delete. Group names can be reused by	deleting and then\nrecreating them with dg_create.','\n',char(10)),'dg','dg_delete group','Nothing if group exists, error otherwise','dg_create, dg_exists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(94,'dg_copy','command',5,'dg_copy','Copy an entire dyngroup to a new dyngroup','dg_copy recursively copies all elements of the old group into a new group.  The lists in the new group are totally separate from the original, and can be manipulated without affecting the the original group.','dg','dg_copy old new','Name of the new group','dl_set, dg_read','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(95,'dg_remove','command',5,'dg_remove','Selectively delete a list from an existing dyngroup',replace('dg_remove provides a means for deleting individual lists from a\ngroup.  This function is only necessary if the contents of the\nspecific list need to be removed before the entire group is\ndeleted with dg_delete, since dg_delete frees all lists in a\ngroup.','\n',char(10)),'dg','dg_remove group list','None','dg_delete, dg_reset','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(96,'dg_read','command',5,'dg_read','Read a saved group from file into memory','dg_read reads a previously stored image of a group into a new group.  If the name of the group that is contained in the file already exists, it will be deleted and replaced by the new group. Saved groups are binary files that are compatible across different computer architectures.  Because groups can contain lists of lists of lists, etc., they cannot be stored in a normal binary file.  Instead, they are stored in tagged files that allow for recursive sublists.  The following example illustrates how lists of lists of lists can be created, written, and retrieved. dg_read will first look for the file named *filename* and attempt to load it.  If this file does not exist, it will search for *filename.dg* and failing that, it will look for  *filename.dgz*.  Note that {<nowiki>\</nowiki>.dgz} files are compressed {<nowiki>\</nowiki>.dg}  files and are almost always preferable because of the considerable space reduction which is achieved with only a slight speed penalty.','dg','dg_read filename [groupname]','The name of the newly created group','dg_write, dg_dump, dl_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(97,'dg_reset','command',5,'dg_reset','Reset all lists in a dyngroup',replace('dg_reset resets all lists in a dyngroup to contain zero elements.\nIt does not remove the lists from the dyngroup, only reset them\nsuch that they are empty.  To completely reset a dyngroup, use\ndg_delete followed by dg_create.','\n',char(10)),'dg','dg_reset group','Name of the reset dyngroup','dl_reset, dl_set, dg_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(98,'dg_exists','command',5,'dg_exists','Checks whether a group already exists','dg_exists is used to check whether a group exists, generally for the purposes of creating a new one if it doesn''t or deleting the old one if it does.','dg','dg_exists group','1 if the group does exist, 0 otherwise','dl_exists, dg_create, dg_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(99,'dg_select','command',5,'dg_select','Selected a subset of rows from a dyngroup','dg_select selects a subset of rows from a dynamic group by applying dl_select to each of its  consituent lists using the sels selection list.  The original group is changed in the process, so dg_copySelected may be preferred, as it returns a new dynamic group. Note that the function dg_choose, which operates by selecting rows by index, is not destructive, so there is an inconsistency between these two apparently similar functions.','dg','dg_select g sels','Name of original group','dg_choose, dg_copySelected, dl_select','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(100,'dg_toJSON','command',5,'dg_toJSON','Convert a dyngroup into a JSON string','dg_toJSON uses the jansson library to turn the dynamic group stored in dg into a string containing lists for each list within the dynamic group.  Importantly, the JSON output supports lists of lists, and, unlike dataframes in pandas or R, there is no expectation that each list is the same length.','dg','dg_toJSON group','JSON object with all of the values from the dynamic group','dg_fromString, dg_toString, dl_toJSON, dg_read, dg_write, dl_write','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(101,'dg_listnames','command',5,'dg_listnames','Prints out list of names of group members','This function returns the names of all the member lists of a dynamic group, as a list of strings.  This function is probably most useful for debugging scripts, since the composition of the group will usually be known ahead of time.','dg','dg_listnames dyngroup','New list of names of members of *dyngroup*','dg_tclListnames, dg_dumpListNames, dg_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(102,'dg_toString','command',5,'dg_toString','Convert a dyngroup into a platform independent byte string','dg_toString is a powerful function that takes a dynamic group and converts it into a byte string that can be stored to disk, sent across sockets to other processes, and converted back to a dyngroup using the dg_fromString function. The dg_toString function, coupled with tcl file io utilities like *open* and *puts* can achieve the same file writing that is encompassed in the dg_write function.','dg','dg_toString group variable_name','Size of the result string in bytes','dg_fromString, dg_toJSON, dg_read, dg_write, dl_write','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(103,'dg_append','command',5,'dg_append','Append one dynamic group onto another',replace('The purpose of this function is to combine two similar sets of data.\nTo this end, both sets must take the form of dynamic groups\ncontaining the same number of lists, where the first list of first\ngroup is of the same type as the first list of the second, the\nsecond list of the first group of the same type as the second list\nof the second, and so on.  The function will then append the\nelements of each list of the second group onto the end of the\ncorresponding list in the first group, modifying the first group in\nthe process.  Note that the various lists do not have to be of the\nsame length, although this would probably be advisable if the list\ndata are related, as might be a list `column` identifying each\n`row` of data.','\n',char(10)),'dg','dg_append to from','Name of modified list *to*','dg_create, dl_append, dl_combine, dl_concat, dl_set','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(104,'dg_view','command',5,'dg_view','View a dynamic group in a tktable widget','dg_view allows dynamic groups to be visualized in table form by loading an existing group into a 2D, spreadsheet like widget.  Scalar values are displayed in individual cells, and lists can be clicked on to open up a new view of the contents of that list.  Note that this function requires the availability of Tk.  In Tcl only environments, however, a dynamic group can be saved to disk using dg_write, and then read back using dg_read on the Tk supported platform.','dg','dg_view group','None','dg_dump, dg_read, dg_write','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(105,'dg_sort','command',5,'dg_sort','Reorders the elements of a dynamic group','The purpose of dg_sort is to reorder the elements of the member lists of a dynamic group.  It works on a group containing one or several member lists, each of the same length.  The group should contain tabular data, with each member list the data from a single column.  The function sorts the lines in this table by the lists `list1`, `list2` etc.  This means that after the lines have been reordered the first list given will be sorted in numerical or alphabetic order, and where the first list contains identical elements, the elements of the second will be sorted.  A practical example of this would be a list of names and addresses stored in a dynamic group, where the first member list contained family names and the second first names.  This table could be sorted by the first list and the second, to order the addresses like a telephone book. If a third list contained the ages of the people in the list, one could also use that to reorder the table.  The foll owing example shows how this is done.','dg','dg_sort dyngroup list1 [list2…]','The newly so rted dynamic group','dg_permute, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(106,'dg_fromCSV','command',5,'dg_fromCSV','Create a dynamic group from a CSV file',replace('dg_fromCSV provides a method for importing CSV files into\ndynamic groups.  By default, a header is assumed to be present\nin the first line, which specifies the column names. If more than\none header line is present, the names are concatenated with a\n''/'' separater to create column names.  If no header is present\nthen columns are names c0 through cN.\n\nDatatypes are one of *int, float, or string* and these are\ndetermined using the first line of data.','\n',char(10)),'dg','dg_asciiRead [-header_start 0] [-header_stop 1] filename','Name of new dyngroup','dg_asciiRead, dg_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(107,'dg_choose','command',5,'dg_choose','Copy a selected subset of rows from a dyngroup to a new dyngroup using row indices',replace('dg_choose does a dl_choose for each list in g using the index selector list and places the result\nin the newly created group.  Because the choice index can be any length, an optional reference list\ncan be specified which says to apply the dl_choose only to lists of the same length as this reference\nlist.\n\nNote that a newly created dynamic group is returned, and the original group is left unaltered.','\n',char(10)),'dg','dg_choose g indices [ref]','Name of the new group','dg_copySelected, dg_select, dl_chooseselect','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(108,'dg_clean','command',5,'dg_clean','Deletes temporary dynamic groups','This function deletes any temporary groups which may be in memory.  Temporary groups are groups which are returned from<nowiki> \</nowiki>dlsh<nowiki>\</nowiki> functions which have not been renamed with dg_rename for storage purposes, usually because they were used by another function as soon as they were created.  They are identified within<nowiki> \</nowiki>dlsh<nowiki>\</nowiki> by their names, which are of the form *group*`xx`.  After being used, these temporary groups do not disappear, but instead remain in system memory, inaccessible for any practical use.  Calling dg_clean allows the memory used by these groups to be freed.','dg','dg_clean','','dl_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(109,'dg_rename','command',5,'dg_rename','Renames a dynamic group, or a list within a group',replace('This function renames either a dynamic group, or a member list of a\ndynamic group, depending on whether the *dynlist* part of the\nname argument is present.  It returns the new name specified if the\nargument is a group, or the name of the list in the form {\tt\ndyngroup:newname}, which may be directly reused by a \dlsh\\nfunction, if the argument is a list.','\n',char(10)),'dg','dg_rename dyngroup[:dynlist] newname','New name of group, or of list','dg_remove, dg_addExistingList, dg_addNewList, dg_copyExistingList','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(110,'dg_addExistingList','command',5,'dg_addExistingList','Add an existing list to a dyngroup',replace('dg_addExistingList moves an existing list is to a dyngroup.  The\nadded list becomes the property of the group, and will be discarded\nwhen the group is deleted with dg_delete.  In order to add a list\nwithout destroying the old list (for example, when copying a list\nfrom one dyngroup to another), use the dg_copyExistingList command.\nIf newname is specified, the list will be given that name, otherwise\nit will inherit the name from the source list.  It is good practice\nto specify a name, otherwise lists created on the fly will end up\nbeing called, for instance *g:%list32%*.  The function will fail\nif an attempt is made to add a list under the name of one a lready\nexisting within the group.','\n',char(10)),'dg','dg_addExistingList group list [newname]','Name of  newly created list','dg_addExistingList, dg_copyExistingList, dg_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(111,'dg_addNewList','command',5,'dg_addNewList','Add a new list to a dyngroup',replace('dg_addNewList is used to add a new list to a dyngroup.  It is\nsomewhat like specifying a structure entry in C, except that no size\nneed be specified, since the list will expand dynamically\n(specifying an initial size may be useful in cases when the final\nsize of the list is known, since this saves reallocation as the list\ngrows).  Once created, the list is accessed by the group:name\nnotation.  The list is deleted when the whole group is deleted.\nNote that lists within groups can be taken out using the dl_set\ncommand.','\n',char(10)),'dg','dg_addNewList group name [datatype [size]]','Name of newly created list','dg_addNewList, dg_copyExistingList, dg_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(112,'dg_dumpListNames','command',5,'dg_dumpListNames','Dump the names of a dynamic group''s list to the screen or a file','dg_dumpListNames prints out a list of column ids and list names which correspond to the names of the lists in the (which is referred to as a database in the output).  Each column can be accessed individually by using the group:listname notation. The list names are preceded by the % character because that character is the comment character for Matlab.  The output format for this function may change in the future.','dg','dg_dumpListNames','None','dg_dump, dl_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(113,'dg_copyExistingList','command',5,'dg_copyExistingList','Copy the contents of an existing list into an existing dyngroup',replace('dg_copyExistingList performs a similar function to dg_addExistingList except that the source list is left intact.  It is thus the correct function to use when copying a list from one group to another, or when one wishes to keep a named dynlist availa\nble for further processing.','\n',char(10)),'dg','dg_copyExistingList dg list [name]','Name of thnewly created list','dg_addExistingList, dg_addNewList, dg_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(114,'dg_create','command',5,'dg_create','Create a new dynamic group',replace('dg_create creates a new dynamic group, as long a group named `\nname` does not already exist.  Once a group is created, it can be\nadded to using the dg_addExistingList, dg_addNewList, or\ndg_copyExistingList functions.  Dynamic groups can be inspected by\ndumping the constituent lists with dl_dump or dl_tcllist, or by\nusing the dg_dump function.  Names of constituent lists can be found\nwith the dg_dumpListNames function.','\n',char(10)),'dg','dg_create name','Name of the new group','dl_create, dg_addExistingList, dg_addNewList, dg_CopyExistingList, dg_delete, dg_dump, dg_dumpListNames, dg_exists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(115,'dg_write','command',5,'dg_write','Write a dyngroup to a disk file for later retrieval','dg_write stores an arbitrary group to a file, using a tagged file format that allows recursively defined structures, such as lists of lists, to be stored to disk.  The binary output file has a magic number composed of a 4-byte string at the beginning (*0x21, 0x12, 0x36, 0x63*) which can be used to identify the file as a stored dyngroup.  In general, the dg_write function is paired, at some later time, with the dg_read function.  To create ASCII output files, see the associated information on dg_dump and dl_dump.   If no output filename is specified, dg_write will by default create a compressed disk file with the name of the group and the *.dgz* extension.  This file can be read back in with dg_read. If an uncompressed file is desired, supply a filename with the *.dg* extension.','dg','dg_write group [filename]','None','dg_read, dg_dump, dl_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(116,'dg_copySelected','command',5,'dg_copySelected','Copy a selected subset of rows from a dyngroup to a new dyngroup',replace('dg_copySelected does a dl_select for each list in g using the selector list and places the result\nin the newly created group.  Lists that are of a different length than sel will be skipped if\nthe save_noteq arg is not specified or passed as 0.  If save_noteq is 1 then these lists will be copied unchanged.','\n',char(10)),'dg','dg_copySelected g selections [save_noteq]','Name of the new group','dg_choose, dg_select, dl_select','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(117,'dg_dir','command',5,'dg_dir','Returns a list of existing dyngroups',replace('dg_dir returns a list of open groups, which may be empty if no\ngroups are currently active.','\n',char(10)),'dg','dg_dir','List of group names','dg_create, dl_delete, dg_exists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(118,'dg_dump','command',5,'dg_dump','Dump the contents of a dynamic group',replace('dg_dump gives a formatted printout of the contents of a group.  For\ncolumnar data, it is particularly useful, because it can be used to\ndump the contents of a dyngroup to an ASCII file (or the screen).\nIf a valid fileid is specified, the output will be directed to the\nopen file.  If no fileid is supplied, output will be printed to the\nscreen.  Because dg_dump prints out each list in a column, elements\nof lists which are themselves lists are printed as a list identifier\n(e.g. *List(5,3)*), which represents a list of datatype 5, with\nthree elements). Also, individual lists of a group need not have the\nsame number of elements, meaning that the dg_dump command must\ncompensate for short lists in a group by printing either *''s\nor  .''s in order to maintain a column''s integrity.','\n',char(10)),'dg','dg_dump group [fileid]','None','dl_dump, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(119,'dl_negate','command',6,'dl_negate','Returns the negative of a list','This function returns a list of identical structure to the argument *dynlist*, but in which every numerical value is replaced by its negative.  If the list contains any strings, the function will fail.','dl','dl_negate dynlist','List of negatives of *dynlist*','dl_add, dl_sub, dl_mul, dl_div','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(120,'dl_flist','command',6,'dl_flist','Create a new float dynlist','dl_flist is tcl procedure that calls dl_create with the float option.  Like dl_create, it accepts optional args to add to the new list.','dl','dl_flist [f0 … fn]','Name of new float list','dl_create, dl_clist, dl_ilist, dl_llist, dl_slist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(121,'dl_collapse','command',6,'dl_collapse','Collapse a recursively defined list into one long list','dl_collapse operates on a list of lists whose elements are all of the same type, and collapses each sublist in order to create a new list. It can be used to unsort lists that have already be en sorted, for example.','dl','dl_collapse list','New list of same type, but one level shallower','dl_combine, dl_concat, dl_reshape, dl_unpack, dl_deepUnpack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(122,'dl_sqrt','command',6,'dl_sqrt','Returns the square root of a list','This function returns a list of floating point values, of similar structure to *dynlist*, in which each number is the square root of the corresponding value in *dynlist*.  If explicit error checking is not enabled, the value *NaN* (Not a Number) will be given if the square root of a negative number is asked for, otherwise the function will return an error, as it will if there are any string values within *dynlist*.','dl','dl_sqrt dynlist','New float list of square roots of *dynlist*','dl_pow, dl_add, dl_sub, dl_mult, dl_div','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(123,'dl_or','command',6,'dl_or','Compares two lists using ``logical or'''' operator','When applied to two scalar values, this function returns a single integer value, equal to 0 if both values are 0, and 1 otherwise.  When applied to a scalar and a list, it returns a list of similar structure, in which each number is replaced by the result of the comparison between it and the scalar.  Finally, if the function is applied to two lists of equal length, it returns a list in which each element is obtained by recursive application of the function to the corresponding elements of the two argument lists.  The function will fail if either of the argument lists contains string values, or if it is applied to two lists of several elements and different lengths.  If one of the arguments is empty, no value will be returned.  The argument lists are always left unchanged.','dl','dl_or list1 list2','Results of logical or between *list1* and *list2*','dl_and, dl_not, dl_ones, dl_zeros','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(124,'dl_slist','command',6,'dl_slist','Create a new string dynlist','dl_slist is tcl procedure that calls dl_create with the string option.  Like dl_create, it accepts optional args to add to the new list.','dl','dl_ilist [s0 … sn]','Name of new string list','dl_create, dl_flist, dl_ilist, dl_llist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(125,'dl_char','command',6,'dl_char','Returns the argument, recast as a char','When used with a number as argument, dl_int recasts that number as a char value, and returns the result.  In practice, this means that the remainder of the value after division by 256, rounded down to the nearest integer value will be returned with the type char.  If this function is applied to a list of numbers, it will return a duplicate of the list in which the function has been applied to each number value.  If applied to a list containing strings, the function will return an error.','dl','dl_char value','New list of chars','dl_int, dl_float, dl_floor, dl_ceil, dl_mod','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(126,'dl_semList','command',6,'dl_semList','Returns the standard error of the mean for each column of a list of lists','When to a list of numbers, this function returns a list of standard errors of the mean for each sublist.','dl','dl_semList dynlist','New list of sems for numbers from each position of each list','dl_sem, dl_sems, dl_stds, dl_bstds, dl_hstds, dl_var, dl_vars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(127,'dl_log','command',6,'dl_log','Returns the natural logarithm of the numbers in a list','When applied to a numerical list, dl_log returns a list of identical structure to the original in which all numbers are replaced by their natural logarithms. If explicit error checking is not on, the function will not fail on values outside the definition range, but instead return -Inf or by NaN.  The function will return an error if the list contains any strings.','dl','dl_log dynlist','List of natural logarithms of numbers in *dynlist*','dl_exp, dl_log10','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(128,'dl_median','command',6,'dl_median','Returns the median value of a list, or of the sublists of a list','This function returns the median value of a list.  The method used for finding the median is the following: the list is sorted, and the value with index one half of the list length is returned.  This method works on lists of strings and lists (in the last case it merely returns the mid-value of the list), so the argument need not a number.  The return value will be a Tcl list if the argument is not of type list.  Note that dl_median is a Tcl function similar to the example shown below.','dl','dl_median dynlist','Median value of list, as a Tcl list or a new dynamic list','dl_mean, dl_medians, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(129,'dl_minIndices','command',6,'dl_minIndices','Returns indices of minimums of sublists','This function is similar to dl_minIndex, except that it treats a list of numerical lists in one call.  It finds the highest value in each sublist of the supplied *dynlist* and returns the results as a list of integer values, of the same length as the argument list.  This function is not recursive: if any of the sublists are of type list or string, the function will simply set the result to -1 in the corresponding element of the returned list.  This function will return an error if *dynlist* is not of type list.','dl','dl_minIndices dynlist','Numerical list of indices','dl_minIndex, dl_maxIndex, dl_maxIndices, dl_min, dl_mins','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(130,'dl_dateToDays','command',6,'dl_dateToDays','Returns the number of days since Jan 1, 1900 given the day-month-year','This function serves to replace an IMSL function (imsl_date_to_days).','dl','dl_daysToDate','Number of days since 1900.','dl_daysToDate','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(131,'dl_sum','command',6,'dl_sum','Sums together all numbers found in a list','This function takes as its argument a dynamic list, which it runs through, summing up all numerical values which it finds.   Non-numbers are ignored, and lists are searched through for more numbers.','dl','dl_sum dynlist','Sum of all numbers as a Tcl list','dl_sums, dl_diff, dl_prod, dl_recip, dl_add','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(132,'dl_unpack','command',6,'dl_unpack','Smoothes out the third level of depth of a list of lists','This function removes a level of a list tree structure.  It takes as its argument a list of lists, each containing sublists of only one type.  It returns a list of lists of similar structure, differing only in that the members of the sublists of the original list of lists become the members of the list of lists.  The function will fail if the argument list is not of the form described.','dl','dl_unpack list','New list of smoothed out lists','dl_collapse, dl_length, dl_depth, dl_deepUnpack, dl_pack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(133,'dl_between','command',6,'dl_between','Checks to see if values fall inside given ranges','This function takes as its argument three lists of compatible structure.  Compatible structure means that at any point in the list tree where one of the three has a sublist, the others have either a sublist of the same length and compatible type, or a single value of compatible type, which is treated as though it were a list of values.  The return list will have a similar structure to the arguments (expanded as much as possible) and will contain the value one wherever the corresponding element of the list *vals* is greater than or equal to that of *low*, but less than that of *high*.  The function will fail if a comparison is attempted between lists of different length, or a string and a number, or if the lists *low* and *high* do not form proper ranges.','dl','dl_between vals low high','New list of boolean values','dl_count, dl_lt, dl_lte, dl_eq, dl_gte, dl_gt','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(134,'dl_interleave','command',6,'dl_interleave','Interleaves the values of two lists','This function returns a dynamic list consisting of the first value of *list1* followed by the first value of *list2*, the second of *list1*, the second of *list2* and so on.  If one list is longer than the other, the remaining values will be added onto the end of the return list.  This function will return an error if the argument lists are of different types.','dl','dl_interleave list1 list2','Interleavened list of same type as argument lists','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(135,'dl_unique','command',6,'dl_unique','Extract unique values from a list (in sorted order)','dl_unique finds all unique values of a list by first sorting the list and then selecting elements which differ from the previous one.  For this reason, unique values will be returned in order.  To access unique values in their original order, one can call dl_rank, which returns a list of integers corresponding to the number of times that element has appeared in the list so far, and use the 0 elements from that list as a selector from the original list.','dl','dl_unique list','List of unique values','dl_rank, dl_select, dl_sort, dl_sortIndices, dl_uniqueNoSort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(136,'dl_reverse','command',6,'dl_reverse','Reverse the elements of a list','dl_reverse simply reverses the order of a list.  It is `not` called recursively on sublists within a list of lists.','dl','dl_reverse list','New list of reversed elements','dl_permute, dl_reverseAll','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(137,'dl_mult','command',6,'dl_mult','Multiply one list by another','This function is identical to dl_mod (see above), except that where dl_mod returns the modulo of the values in *list1* by those of *list2*, it returns the product of the values in the two lists, and that the lists are of type float rather than type integer.','dl','dl_mult list1 list2','List of products of *list1* by *list2*','dl_div, dl_add, dl_sub','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(138,'dl_bsort','command',6,'dl_bsort','Sort lowest level lists maintaining the upper list structure','For a list of numerical values, dl_bsort returns a list built from the same elements as the input list, but reordered from smallest to greatest.  For a list of strings, dl_bsort reorders the elements alphabetically.  For a list of lists, the function is applied recursively, and a list is returned in which each element is formed by applying dl_bsort to the corresponding element of the input list. In all cases, the return value is the resulting list. *dl_bsort* is functionally identical to *dl_sort* but the added ''b'' makes it clear that it can be mixed with other *dl_b** functions.','dl','dl_bsort list','New list','dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(139,'dl_log10','command',6,'dl_log10','Returns the base 10 logarithm of a list','This function is analogous to dl_log, except that it computes base 10, rather than natural, logarithms.  Use *dl_pow 10 list* to inverse this function.','dl','dl_log10 dynlist','List of base 10 logarithms of values in *dynlist*','dl_log, dl_pow, dl_exp','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(140,'dl_setFormat','command',6,'dl_setFormat','Set the format string for a datatype when printed with dl_dump','This function sets the format strings used for displaying the contents of lists with dl_tcllist and dl_dump.  Normally there should be no need to change the default values (%d for char, short and long, %f for floats, %s for strings and List(%d,%d) for lists, where the arguments for a list are type and length).  The function will fail if name does not name a %%\%%dlsh%%\%% data type.  Also note that the format string should be set correctly, in particular regarding number of arguments; results will otherwise be unpredictable.','dl','dl_setFormat type format','Previous format string for that type, as a Tcl string','dl_dump, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(141,'dl_create','command',6,'dl_create','Create a dynamic list','dl_create creates and optionally initialises a new dynamic list.  The list created will have the type specified by the *datatype* parameter, or long if no data type is supplied, and the number of elements will start off as the smallest multiple of 15 which can hold the initial data.  dl_create *datatype* may be abbreviated to *dl_ilist* for data type long, *dl_flist* for floats, *dl_slist* for strings or *dl_llist* for data type list.  The most common use for dl_create is for manually entering data into a programme (as shown in most of the examples in this chapter). Numerical lists may also be directly entered within double quotes (" ") or curly brackets ({ }).  If you enter a list which you do not need straight away, you can rename it using dl_set or dl_local.','dl','dl_create datatype initial_vals…','A new list','dl_local, dl_set, dl_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(142,'dl_combineLists','command',6,'dl_combineLists','Takes lists of lists as arguments and returns single list created by combining all inner lists of same index.','dl_combineLists creates a new list composed of sublists with each element of the same index packed into a list.  This list can be collapsed in order to interleave lists into a single list.','dl','dl_combineLists l1 l2 etc','New list composed of combined lists','dl_combine, dl_interleave, dl_transpose','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(143,'dl_bins','command',6,'dl_bins','Create a list of bin positions using the same args as dl_hist',replace('dl_bins is a companion function to dl_hist and dl_hists,\nbecause it uses the same algorithm as those functions to\ncreate a series of linearly spaced bins that are most often\nused for creating histograms.  The algorithm simply divides\nthe range between *min* and *max* into *nbins*\nequally spaced intervals, and returns the midpoint of each interval.\nThe output list from dl_bins often is used as the  x-axis data\nin a histogram.','\n',char(10)),'dl','dl_bins min max nbins','List of floats corresponding to center of each bin','dl_hist, dl_hists, dl_series','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(144,'dl_sinh','command',6,'dl_sinh','Returns the hyperbolic sine of a list','This function takes a list of numbers as its argument and returns a list of floats of identical structure, but in which each number is replaced by its hyperbolic sine.  If the argument list contains any values other than numbers or lists, the function will fail.','dl','dl_sinh dynlist','New float list of hyperbolic sines of *dynlist*','dl_cosh, dl_sin','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(145,'dl_bsums','command',6,'dl_bsums','Sum up the lowest levels of a list, without modifying list structure','This list operates on a list of numbers several levels deep.  It returns a list which is identical to the argument, except that every list of a numerical type within the list structure is replaced by the sum of its members.  If the list tree contains any lists of strings, an error will be returned.  This function differs from dl_sums in that it maintains the list structure.','dl','dl_bsums list','New list, summed at lowest level','dl_sums, dl_bmeans, dl_breverse, dl_bsort, dl_bstds, dl_sum','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(146,'dl_not','command',6,'dl_not','Returns logical not of list','This function returns a list of identical structure to *dynlist*, which contains the value 0 in the place of every non-zero number in *dynlist* and 1 in the place of every zero. If the list contains any strings, an error will occur.  The argument list is not changed.','dl','dl_not dynlist','Logical not of values in *dynlist*','dl_or, dl_and, dl_equal, dl_zeros, dl_ones, dl_noteq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(147,'dl_replace','command',6,'dl_replace','Replace elements of a list with substitute elements','The dl_replace function takes particular elements of a list and replaces them with elements from the replacement list.  The selection list is similar to that used for dl_select, and is a boolean list (0s and 1s) with a length equal to the length of the original list.  The replacement list can be either a list of one element, in which case the same replacement is always used, or n-elements, where n is the same size as the source list.  The program will try to convert the replacement elements to the same type as the elements of the list in which they are to be inserted.  If it fails in this, it returns an error.','dl','dl_replace list selections replacement(s)','New list of substituted list','dl_find, dl_select, dl_choose, dl_replaceByIndex','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(148,'dl_permute','command',6,'dl_permute','Returns a list composed of specified elements of another list.','dl_permute is used to rearrange the elements of the list {%%\%%tt dynlist}.  It outputs a list of the same type as *dynlist* and of the same length as *indices*, in which the n-th member is that member of *dynlist* indexed by the n-th element of {%%\%%tt indices}.  If *indices* is not of type integer, the function will return an error.  Any out of range indices will be ignored.','dl','dl_permute dynlist indices','New list of *indices* elements of *dynlist*','dl_transpose, dl_reverse, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(149,'dl_index','command',6,'dl_index','Replace each element of a list with its respective list position','dl_index indexes a list by replacing all list elements with their corresponding list position.  It is used, for example, to locate all of the first elements of a list (or list of lists).  When combined with dl_select or dl_replace, it is possible to select or replace the first element of every list in a complex structure.','dl','dl_indices list','List of same structure of positions','dl_indices, dl_select, dl_replace','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(150,'dl_zrand','command',6,'dl_zrand','Returns a list of pseudo-normally distributed random values','When called with an integer as argument (a float will be rounded down to the nearest integer), dl_zrand returns a pseudo-normally distributed random number.  When called with a list as argument, dl_zrand will apply itself recursively to each element and return the result as a list, unless the argument list contains string values, in which case the call will fail.','dl','dl_zrand size','New float list of random numbers','dl_irand, dl_urand, dl_randchoose','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(151,'dl_parzen','command',6,'dl_parzen','','','dl','','','dl_parzens, dl_sdf, dl_sdfs','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(152,'dl_critz','command',6,'dl_critz','Compute critical Z value to produce given probability','dl_critz uses an algoritm adapted from a polynomial approximation in: Ibbetson D, Algorithm 209, Collected Algorithms of the CACM 1963 p. 616, as implemented by Gary Perlman to approximate z values. dl_critz returns a list of $z_{1-%%\%%alpha}$ values,  which correspond to the distance in z-units from the center of the  normal distribution at which the probability that a normal random deviate will be less than supplied argument. For example, *dl_critz 0.5* corresponds to the center of the normal distribution, and hence $z_{1-%%\%%alpha}$ will be 0.','dl','dl_critz $1-%%\%%alpha$','list of $z_{1-%%\%%alpha}$ values','dl_poz, dl_critf, dl_pof','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(153,'dl_tanh','command',6,'dl_tanh','Returns the hyperbolic tangent of a list','dl_tan returns a list of numbers of identical structure to the argument *dynlist*, but one in which each number value is replaced by its tangent.  If the list contains strings at any level, an error will be returned by the function.','dl','dl_tanh dynlist','New list of hyperbolic tangents','dl_sinh, dl_cosh, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(154,'dl_findAll','command',6,'dl_findAll','Find all target patterns in a source list','The dl_findAll function is like the dl_find function, but it searches for all, not just the first, occurrence of targets in the source list.','dl','dl_findAll source target','If the args are a list of scalars and a scalar, returns list of indices of occurrence (the list will be empty if none are found). If the args are a list of scalars and a list of patterns, returns a list of integer pairs where the first index represents which target pattern was found and the second represents where in the source it was found.','dl_find','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(155,'dl_breverse','command',6,'dl_breverse','Reverse elements of lowest level lists, retaining higher structure','For a list of elements other than lists, dl_breverse reverses the order of the elements, and returns the result.  For a list of lists, the function is applied recursively.  Therefore, the returned list will differ from the original only at the lowest level of each list tree.  The similar dl_reverse and dl_reverseAll functions on the other hand return a list with a different structure to the original.','dl','dl_breverse list','New list','dl_reverse, dl_reverseAll','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(156,'dl_cleanReturns','command',6,'dl_cleanReturns','Delete temporary lists that are no longer needed','dl_cleanReturns deletes lists that were returned using dl_return and that have not been renamed, added to a group, or deleted  explicitly.  It is not normally used in current dlsh scripts.','dl','dl_cleanReturns','None','dl_clean, dl_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(157,'dl_parzens','command',6,'dl_parzens','','','dl','','','dl_parzen, dl_sdf, dl_sdfs','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(158,'dl_reverseAll','command',6,'dl_reverseAll','Reverse the elements of a list recursively','dl_reverseAll is identical to dl_reverse when the list to be reversed is not a list of lists.  For lists of lists, however, all sublists are also reversed.','dl','dl_reverse list','New list of reversed elements, with sublists reversed','dl_permute, dl_reverse','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(159,'dl_uniqueCross','command',6,'dl_uniqueCross','Returns unique crosswise set of elements in list','The function dl_uniqueCross is used for indexing a multi-dimensional array of lists.  This works in the following way: the argument lists *list1*, *list2*, etc are considered as the axes of a finite *n*-dimensional Cartesian space.  Each element of the argument lists is considered to be an offset in that dimension, and every point in the space can be referred to by choosing exactly one element from each list.  Since the number of points accessible in this way is equal to the product of the number of unique elements in each argument list, the *n* returned lists each contain that number of elements.  Within these returned lists, the *i*-th element is a co-ordinate of the *i*-th point in the Cartesian space, and when the function is used to index *n*-dimensional arrays represented as lists of lists, the *i*-th sub-list corresponds to that point in space.  Note that the return value of this function is identical to that which would be obtained by dl_cross if the argument lists contain only unique values and are sorted.  The function will fail if the argument lists contain sub-lists, or if only one is supplied.','dl','dl_uniqueCross list1 list2 […] listn','New list of possible products of list elements','dl_cross, dl_sortByLists, dl_sortBySelected','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(160,'dl_meanList','command',6,'dl_meanList','Calculates the mean values of each column of multiple lists','This function operates on a list of numerical lists and returns the  mean value for each column (position) of the input lists.  Each sublist must be the same length.','dl','dl_meanList dynlist','List of column mean values of lists','dl_means, dl_hmeans, dl_bmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(161,'dl_tcllist','command',6,'dl_tcllist','Converts a dynamic list to a JSON encoded list','*dl_toJSON* converts a dynamic list into a JSON encoded string using the jansson JSON library.  It is similar to *dl_tcllist*, but the format of the output string is JSON formatted.  This can be used to move data between Tcl and many other environments (e.g., python, MATLAB, R, or Javascript).','dl','dl_toJSON dynlist','*dynlist* as a JSON encoded string','dg_toJSON, dl_dump, dl_dumpAsRow, dl_dumpMatrix, dl_dumpMatrixInCols','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(162,'dl_repeat','command',6,'dl_repeat','Repeat each element of source list a certain number of times','When called with *count* as a single value, this function returns a list of the same type as the argument list, but in which each member is duplicated *count* times.  When called with *count* as a list of integers of the same length as *source*, dl_repeat returns a list in which value within *source* is repeated as many times as the corresponding element of *count*.  If *count* is a list of different length to *source*, or if it does not contain integers, an error will be returned.  Negative *count* values are treated as zeros.','dl','dl_repeat source repeats','New list of repeated values','dl_choose, dl_repeatelements_dl_replicate','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(163,'dl_stringmatch','command',6,'dl_stringmatch','Returns logical vector for matches with wildcard specs','Returns logical vector for matches with wildcard specs','dl','dl_stringmatch dynlist matchlist','List of 1''s and 0''s','dl_setFormat, dl_slist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(164,'dl_fileext','command',6,'dl_fileext','Return the extension of a filename','dl_fileext is used for extracting the extension - that is to say, removing any directory and file names - from filenames.  It takes as its argument a list of names, and returns a list of the corresponding extensions.','dl','dl_fileext dynlist','New list of file extensions','dl_filebase, dl_filedir, dl_fileroot, dl_filetail','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(165,'dl_lengths','command',6,'dl_lengths','Gives the lengths of several dynamic lists','This function works similarly to dl_length, but instead of returning the length of a single list, it counts the number of elements in each sublist of *dynlist*, and returns the result as a list.  This function will fail if *dynlist* is not a list of lists.','dl','dl_lengths dynlist','List of lengths of lists in *dynlist*','dl_length, dl_llength, dl_count, dl_counts, dl_lcounts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(166,'dl_depth','command',6,'dl_depth','Find the maximum depth of a list','dl_depth traverses down a list, finding the deepest branch.  A list of scalars is considered depth 0, a list of lists of scalars is depth 1, and so on.','dl','dl_depth list','integer','dl_collapse, dl_length, dl_lengths, dl_unpack, dl_deepUnpack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(167,'dl_fitfunc','command',6,'dl_fitfunc','','','dl','','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(168,'dl_sdf','command',6,'dl_sdf','Compute spike density function for a list of times','Compute spike density function for a list of times','dl','dl_sdf times start stop kernel_sd kernel_nsds resolution','spike density function sampled every *resolution* ms','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(169,'dl_sublist','command',6,'dl_sublist','Checks whether a list is a sublist of another','This function checks whether its argument is a sublist of another list.  It returns one if this is the case, nought otherwise and minus one if the argument is not a valid dynamic list.','dl','dl_sublist dynlist','Tcl boolean value, or minus one on failure','dl_exists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(170,'dl_llist','command',6,'dl_llist','Create a new list dynlist','dl_llist is tcl procedure that calls dl_create with the list option.  Like dl_create, it accepts optional args to add to the new list.  Note that lists passed to the new list are copied onto the new list.','dl','dl_llist [l0 … ln]','Name of new list list','dl_create, dl_ilist, dl_flist, dl_slist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(171,'dl_firstPos','command',6,'dl_firstPos','Returns logical mapping with 1s for first elements and 0s elsewhere','This function returns a list that can be used as general selector for the first element of all sublists in the input. It is primarily used when the input may have empty lists because in that case the structure of the return will still be appropriate for calling dl_select.','dl','dl_firstPos list',replace('List of the same structure as the\ninput *dynlist*','\n',char(10)),'dl_first, dl_last, dl_get, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(172,'dl_prepend','command',6,'dl_prepend','Inserts values at the beginning of a dynamic list','This function inserts values at the beginning of a dynamic list, modifying the list in the process.  The values will be prepended in the order in which they are given, which means that they will appear in the reverse order in dynlist after the operation.  The values given must be compatible with the list type of the list.  The return value is the new value of *dynlist*.  Note that using this function within a Tcl loop is not recommended, due to speed considerations.','dl','dl_prepend dynlist val(s)','New value of *dynlist*','dl_append, dl_insert, dl_put','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(173,'dl_series','command',6,'dl_series','Returns an evenly spaced series of numbers','When applied to two or three numbers, dl_series returns a series of numbers starting with the value *start*, between start and stop and increasing by the value step, or by one if step is not supplied.  When applied to two or three lists of numbers of the same length, dl_series returns a list of that length in which each member is formed by applying dl_series to the corresponding members of the arguments.  Finally, when applied to a mix of scalars and lists, the scalars are treated as lists filled with a single value, and the function is applied as to lists.  The function will return an error if it is applied to lists of different lengths, or lists containing strings, or if the *stop* value is less than (greater than for negative *steps*) the *start*.','dl','dl_series start stop [step]','New list of numbers, or of lists of numbers','dl_fromto, dl_bins','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(174,'dl_mean','command',6,'dl_mean','Calculates the mean value of a list','When applied to a list of numerical values, this function returns the mean of the list as a Tcl integer value.  When applied to a list of lists, the function is applied recursively to each sublist, and the return value is the mean of the values thus obtained.  Applied to an empty list, or to a list of strings, this function returns 0.  Note that the return value when applied to a list several levels deep is not the mean of all values in the list, since the weightings will usually vary.','dl','dl_mean dynlist','Mean value of *dynlist*','dl_means, dl_bmeans, dl_hmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(175,'dl_float','command',6,'dl_float','Cast a numeric list to be of type float','When applied to a numerical list, dl_float recasts all values in the list as floats, and returns the result as a list of floats.  When applied to a list of lists, dl_float applies itself recursively to all member lists and returns the result.  In both cases, the original list is left unchanged.  If the function is applied to a list of strings, an error will result.','dl','dl_float list','New list that mirrors *list* but of type float','dl_int, dl_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(176,'dl_round','command',6,'dl_round','Round each value of a list to the nearest int','When applied to a list of floating point or integer values, this function rounds them to the nearest integer value, leaving values which are already integer untouched, and returns the result as a list of integers.  When applied to a list of lists, this function applies itself recursively to each sublist, and returns the resulting list.  In all cases, the original list is left unchanged.  If this function is applied to a list of strings, an error will result.  This function seems in practice to be identical to dl_int.','dl','dl_round list','List of floats corresponding to rounded values of the list','dl_ceil, dl_floor, dl_int','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(177,'dl_countOccurences','command',6,'dl_countOccurences','The dl_countOccurences function counts the number of times targets appear in a source list','dl_countOccurences returns a list of counts corresponding to the number of occurrences of each pattern in the source.  Patterns can be scalars or lists.  In either case, the length of the return list is exactly the same length as the pattern list.  If no patterns are found this list will be all zeros.  Note that this functions makes counting elements by combining dl_eq with dl_sum unnecessary.','dl','dl_countOccurences source pattern','A list of counts, one for each pattern','dl_findAll, dl_find','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(178,'dl_find','command',6,'dl_find','Find a pattern of values inside a list',replace('The dl_find function can be used to find an instance of a target\nelement in a source list.  To find all elements, use dl_findAll.\nIn the most basic format, the target is a single value and dl_find\nreturns the index of the first instance of target in source.\nIf, however, a list of alternatives is supplied as a list of\ntargets, dl_find returns the index of the target found followed\nby the index in the source list where that target can be found.','\n',char(10)),'dl','dl_find source target',replace('If the args are a list of scalars and a scalar, returns index\nof first occurrence or -1\nIf the args are a list of scalars and a list of patterns,\nreturns the index of the pattern and the index of the source list.','\n',char(10)),'dl_findAll','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(179,'dl_fill','command',6,'dl_fill','Create a regularly spaced array from sparse data','This function is used to regularly to sample a time series, based on information about the times when the value of the data read changed.  It takes as its arguments two numerical lists, corresponding to the values taken by the data, and the times as of when the data took on those values.  It also takes as arguments the times between which data sampling'''' should take place, and optionally the time interval between samples.  Depending on the datatype of *values*, the return value will be a list of longs or of floats, of length (*stop* - *start*) / *res*. This function will return an error if the lengths of the lists *values* and *times* are different, if any of the variables are not of a numerical type, or if *start* and *stop* do not form a proper time range (for instance if *start* is greater than *stop*).  If the sampling starts before the first time in the list, the first series value is used.','dl','dl_fill values times start stop [res]','List of same datatype as *values*','dl_hist, dl_hists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(180,'dl_prod','command',6,'dl_prod','Returns the product of all values in a list','dl_prod returns the product of all numbers in a numerical list.  The list may be a simple list of numbers, or contain several different levels, but the result will not reflect the particular structure of the list.  A list of strings as an argument will be ignored, and an empty list will return 1.','dl','dl_prod dynlist','Product of values in *dynlist* as a Tcl list','dl_prods, dl_cumprod, dl_sum, dl_diff','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(181,'dl_gte','command',6,'dl_gte','Compare elements of arg1 and arg2 using greater than or equal to relation','When applied to two scalar values, dl_gt will return 1 if the first is greater than or equal to the second, and 0 otherwise.  If applied to two strings, dl_gt will return 1 if the first string comes alphabetically later than or is equal to the second.  If applied to two identical lists, dl_gt will return a list in which the n-th element is obtained by recursive application to the n-th elements of the first and second lists. If applied to a list and a single scalar or string value, the function will be applied recursively between each element of the list and the single value.  In the first two cases, the return value will be a list of type long, in the third and the forth, a list of type list.  If the two arguments are not of the same type, an error will result.','dl','dl_gte arg1 arg2','List of (lists of) boolean values','dl_gt, dl_lt, dl_lte, dl_eq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(182,'dl_randfill','command',6,'dl_randfill','Reorders the first *n* integers at random.','This function acts similarly to dl_randchoose.  It takes as its argument an integer, or a structured list of integers, and returns a list of similar structure in which each integer value *n* of *dynlist* is replaced by a list.  This list is a random reordering of the first *n* integers, such as might be obtained by calling `dl_randchoose *n n*`.  The call will fail if *dynlist* contains values other than positive integers.','dl','dl_randfill dynlist','List of (lists of) reordered integers','dl_randchoose','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(183,'dl_reshape','command',6,'dl_reshape','Arranges the elements of a list into a matrix of lists','This function splits up *dynlist* into *rows* smaller lists, each of length *cols*, and returns the result as a list of lists.   For the function to work, the number of elements in *dynlist* must be equal to the product of *rows* and *cols*, which must in turn be single integer values.  *dynlist* may be of any type, but if it is a list of lists, the function will work on the top level lists rather than recursively.','dl','dl_reshape dynlist rows cols','New list of lists of values in *dynlist*','dl_isMatrix, dl_transpose, dm_functions','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(184,'dl_mod','command',6,'dl_mod','Calculates the remainder of a list divided by another','This function returns the remainder of *list1* after division by *list2*.  If *list1* is a single value, this function will return the remainders of *list1* by each element of *list2* as a list.  If *list2* is a single value, it will return the remainders of each member (possibly just one) of list1 divided by *list2*.  If both are lists of the same length, the return value will be a list of that length in which each element is obtained by recursively applying the function to the corresponding elements of *list1* and *list2*.  This function will fail if it is applied to two lists of several values and different lengths, or if it is applied to a list containing string values.','dl','dl_mod list1 list2','List of remainders of *list1* after division by *list2*','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(185,'dl_set','command',6,'dl_set','Gives a name to a dynamic list','This function gives a name to a dynamic list, or duplicates it under a new name if it already has a name, and is not a temporary list.  Lists assigned temporary names (*%list{%%\%%it xx* %}) in this way will be treated as temporary lists by %%\%%dlsh.  This function is useful for preserving function return values, but the dl_local function is normally to be preferred over it, because lists created or named using dl_local will automatically be deleted when the function in use returns, which saves having to do this by hand.  Another use for this funciton is to remove lists from dymamic groups without erasing the list.  By setting the name of a list in a group to that of a standard dynamic list, the list will be transfered to the list of free dynamic lists.','dl','dl_set name dynlist','*dynlist* under its new name','dl_local','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(186,'dl_daysToDate','command',6,'dl_daysToDate','Returns the day-month-year corresponding to number of days since Jan 1, 1900','This function serves to replace an IMSL function (imsl_days_to_date).','dl','dl_daysToDate','Day month year of corresponding number of days since 1900.','dl_dateToDays','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(187,'dl_choose','command',6,'dl_choose','Choose elements out of one list using a list of indices','The function dl_choose returns the *n*th element of the list *list*, where an index of 0 refers to the first element.  If the element indexed does not exist, for example if the index is too high, an error will occur.  If *list* is a list of lists, then *n* may be replaced by a list.  In this case, dl_choose will be applied recursively to each element of *list*, using the corresponding element of *n* as an index, and the results will be returned as a list.  Note that in this case, *list* and *n* must contain the same number of elements, or an error will occur.  This function can be useful in building tables (see examples).','dl','dl_choose source selections','list of same type as first argument','dl_select, dl_get','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(188,'dl_max','command',6,'dl_max','Returns the maximum value of a list','This function runs through a supplied list *dynlist* and returns the highest numerical value which it finds, as a Tcl integer. The list may have several levels.  Any string values found will be ignored.  If several argument lists of similar structure are supplied, dl_max will return a single new list of such a structure.  Each element of this new list will be the maximum of the corresponding elements in the argument lists; this means that if dl_max is called with three lists of five integers, it will return a list of five integers in which the first element is the maximum of the first elements of each argument list, the second the maximum of the second elements and so on.  If it is called with two lists of five and a single number, the number will be treated as a list of five times itself.  If any of the argument lists contain floats, the returned list will contain floating point values.','dl','dl_max dynlist (…)','The maximum of *dynlist*','dl_maxs, dl_min, dl_mins, dl_maxIndex, dl_maxIndices','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(189,'dl_lgamma','command',6,'dl_lgamma','Returns the natural logarithm of gamma of a dynlist','When applied to a list of numbers, this function returns a list of type float, in which each value is equal to the natural logarithm of gamma of the corresponding value of the original list.  If the function is applied to a list of lists, it will return a list in which each element is the result of applying dl_lgamma recursively to each element.  In other words, when applied to a numerical list, dl_lgamma will return a list of identical structure, in which each numeric value of the original list is replaced by its natural logarithm of gamma.  This function will fail if there are any strings in the list hierarchy of *dynlist*.  Note however, that if explicit error checking is not turned on, it will succeed if there are values in the list which give an infinite or undefined result, returning `Inf` and `NaN` respectively.','dl','dl_lgamma dynlist','Float list of ln of gamma of *dynlist* elements','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(190,'dl_dumpAsRow','command',6,'dl_dumpAsRow','Dump the values of a list, as a row, to screen or open file','This function works similarly to dl_dump, except that it outputs in rows rather than on separate lines.','dl','dl_dumpAsRow list [fileid]','None','dl_setFormat, dl_tcllist, dl_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(191,'dl_oneof','command',6,'dl_oneof','Looks in source list for one of the elements of the search list','This function returns a logical list very much like dl_eq.  The main difference is that unlike dl_eq, dl_oneof will place a one in the result list if any of the elements in the search list are found in the source.','dl','dl_oneof sourcelist searchlist','A list of zeros and ones, with ones at match positions','dl_eq, dl_stringmatch, dl_or','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(192,'dl_insert','command',6,'dl_insert','Inserts a new element into a dynamic list','This function inserts values into a dynamic list at position *pos*.  The arguments are not modified.  This function will return an error if *pos* is not an integer, or if it is out of range.  It will also return an error if some of the values in {%%\%%tt val(s)} are incompatible with the list type.','dl','dl_insert dynlist pos val(s)','List of same type as *dynlist*','dl_append, dl_prepend','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(193,'dl_vars','command',6,'dl_vars','Calculates the standard deviations of variables over several lists','This function works on a list of lists, returning a list of lists of the same size.  It operates on the members of the sub-lists of the top-level list, which must be numbers, or numerical lists of identical structure.  In the return value of the function, these  elements are replaced by a list of floats of the same structure, in which each element is the variance of the corresponding elements in the original lists.  A practical example of this might be a process in which several data sources were sampled simultaneously, and the results stored in a list data structure.  If the results of several samplings were stored within a list within a list, and the function dl_vars then applied, the resulting list within a list would contain a list data structure holding the standard deviations of all experimental variables.  The function will fail if *dynlist* contains string elements, or if the list structure is not suitable for the function.','dl','dl_vars dynlist','New list of lists of variances','dl_means, dl_stds, dl_var, dl_hvars, dl_bvars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(194,'dl_pow','command',6,'dl_pow','Raises a list to the power of another list','When applied to two numbers, dl_pow returns the first to the power of the second as a one element list.  When applied to a number and a list, the return value is a list containing the results of raising the number to the power of each element of the list.  When applied to a list and a number, the return value is a list of the results of raising each list element to that power.  Finally, when applied to two lists of the same length, dl_pow returns a list in which each member contains the result of raising the corresponding value in the first list to the corresponding power in the second. If explicit error checking is not on, this function can return NaN (not a number), for example if asked for the square root of -1. If either list contains strings, or if the two lists have different lengths of more than one, an error will be returned.','dl','dl_pow vals powers','New list of numbers','dl_sqrt, dl_add, dl_sub, dl_mult, dl_div','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(195,'dl_eq','command',6,'dl_eq','Compare elements of arg1 and arg2 for equality','If both arguments of dl_eq are lists of one element, the function will return 1 if the two are identical or 0 if not.  If the two are not of comparable types, an error will occur.  If just one of the arguments contains more than one element, then dl_eq will return a list containing the same number of elements, showing the results of the comparison of each element to the single argument.  Finally, if both arguments are lists of the same length, dl_eq will return a list of their length containing the results of a member-by-member recursive application of the function. If the two arguments are lists of different lengths, an error will arise.','dl','dl_eq arg1 arg2','List of (lists of) boolean values','dl_gt, dl_gte, dl_lt, dl_lte','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(196,'dl_lastPos','command',6,'dl_lastPos','Returns logical mapping with 1s for last elements and 0s elsewhere','This function returns a list that can be used as general selector for the last element of all sublists in the input. It is primarily used when the input may have empty lists because in that case the structure of the return will still be appropriate for calling dl_select.','dl','dl_lastPos list',replace('List of the same structure as the\ninput *dynlist*','\n',char(10)),'dl_first, dl_firstPos, dl_last, dl_get, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(197,'dl_exp','command',6,'dl_exp','Return elementwise exp(x) of a list','This function returns the exponent of a scalar value as a float.  For a list, the function is applied recursively to each element, and the result is returned as a list.','dl','dl_exp list','New list of exp transformed values','dl_log','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(198,'dl_bsortIndices','command',6,'dl_bsortIndices','Gives the indices of list elements, sorted by order of elements','When applied to a list of numbers, dl_bsortIndices returns a list of integers of the same length, in which the first element is the index of the smallest value in the list, the second the index of the second smallest and so on.  Applied to a list of strings, the function works in a similar way, but the sorting is done by alphabetical, not numerical order.  Finally, when applied to a list of lists,  dl_bsortIndices applies itself recursively to each list element, and returns the results as a list of lists.  This function appears to be identical to dl_sortIndices.','dl','dl_bsortIndices dynlist','Sorted indices of list elements','dl_sortIndices, dl_sort, dl_bsort, dl_recode','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(199,'dl_sums','command',6,'dl_sums','Calculate sums of lowest-level elements of a list','This function is similar to dl_sum, but instead of returning the sum of a single list, it applies dl_sum to each member of a list of lists and returns the result as a list of integers.  The function will fail if it is applied to something other than a list of lists.','dl','dl_sums dynlist','New list of summed lists','dl_prods, dl_sum, dl_add','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(200,'dl_help','command',6,'dl_help','Dump list of dl commands','This command prints out a list of all dynlist commands to the screen, followed by a brief description of what they do.  It would be useful for quickly checking up on a command if the list was not so long, but in its present form, it takes rather a lot of searching to find out anything useful.  A slightly more sophisticated help function, which could search for patterns in command names or descriptions, with perhaps a small amount of online documentation, might be worth considering.  Note that most dynlist commands print out a reminder of their syntax if they are executed without arguments.','dl','dl_help','None','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(201,'dl_tan','command',6,'dl_tan','Returns the tangent of a list','dl_tan returns a list of numbers of identical structure to the argument *dynlist*, but one in which each number value is replaced by its tangent.  If the list contains strings at any level, an error will be returned by the function.  Note that this function should not fail due to infinite results, due to the limited precision of the argument values.','dl','dl_tan dynlist','New list of tangents','dl_sin, dl_cos, dl_atan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(202,'dl_spline','command',6,'dl_spline','Computes spline interpolation curve at points *xinterp*','This function fits a spline curve to the points given by *xlist* and *ylist*, optionally with the slopes of the curve at the first and last points.  It returns a list of floating point values corresponding to the values of the interpolated spline curve at the points *xinterp*.  The function will fail if the size of *xlist* does not correspond to that of *ylist*, or if the arguments are not numbers.','dl','dl_spline xlist ylist xinterp [yp1] [ypn]','New list of values of interpolated curve at points *xinterp*','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(203,'dl_regmatch','command',6,'dl_regmatch','Returns logical vector for matches using regular expressions','Returns logical vector for matches using regular expressions','dl','dl_regmatch ?options? dynlist regexp','List of 1''s and 0''s','dl_stringmatch, dl_regexp','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(204,'dl_asin','command',6,'dl_asin','Take the elementwise arcsine of a list','For lists of numeric values, dl_asin returns a list of the arc sines, in the range of 0 to pi, of the elements of the  provided list.  For lists of lists, the function is  applied recursively.  The returned list is always a list of floats.  NaN is returned for any arguments outside the range [-1,1] if explicit error checking is not on, otherwise an error is returned.','dl','dl_asin list','New list of arcsine transformed values','dl_acos, dl_atan, dl_cos, dl_sin, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(205,'dl_noteq','command',6,'dl_noteq','Compare elements of arg1 and arg2 for inequality','If both arguments of dl_noteq are lists of one element, the function will return 1 if the two are not identical or 0 otherwise.  If the  two are not of comparable types, an error will occur.  If just one of the arguments contains more than one element, then dl_noteq will return a list containing the same number of elements, showing the results of the comparison of each element to the single argument.  Finally, if both arguments are lists of the same length, dl_noteq will return a list of their length containing the results of a member-by-member recursive application of the function. If the two arguments are lists of different lengths, an error will arise.','dl','dl_eq arg1 arg2','List of (lists of) boolean values','dl_gt, dl_gte, dl_lt, dl_lte, dl_eq, dl_not','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(206,'dl_fileroot','command',6,'dl_fileroot','Return the root part of a filename','dl_fileroot is used for extracting the root name - that is to say, stripping off the extension - from filenames.  It takes as its argument a list of names with paths, and returns a list of the corresponding roots.','dl','dl_fileroot dynlist','New list of file name roots','dl_filebase, dl_filedir, dl_fileext, dl_filetail','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(207,'dl_rank','command',6,'dl_rank','Ranks the appearance of values in a list','This function runs through a list of values, and for each one determines the number of times it has appeared up until then in the list.  These counts are returned as a list of integers.  The function will fail if the argument list is of type list.','dl','dl_rank dynlist','List of integer rankings','dl_count, dl_counts, dl_lcounts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(208,'dl_dotimes','command',6,'dl_dotimes','Repeat an operation a given number of times','The purpose of this function is to repeat an operation a number of times.  The Tcl procedure, or short section of code to be executed is given as the argument `body`.  The number of times that this code section is to be called is given as the variable `count`.  Finally, `var` is the name of the variable to be used as a counter.  This will be incremented each time the procedure is executed, and can be used for indexing an array or suchlike.','dl','dl_dotimes var count body','None','dl_foreach','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(209,'dl_hvars','command',6,'dl_hvars','Returns a list of ``horizontal'''' variances for several sets of data','This function operates on a three level deep list of numerical structures.  For it to succeed, the members of the top-level list must be suitable for application of the dl_vars function.  The returned list is then the result of applying dl_vars to each member.  See the descriptions of dl_hmeans and dl_vars for more information.','dl','dl_hvars dynlist','A list of lists of lists of variances','dl_hmeans, dl_hstds, dl_vars, dl_var, dl_bvars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(210,'dl_shift','command',6,'dl_shift','Shifts the elements of a list','This function returns a copy of a dynamic list in which the elements are shifted relative to their original positions.  If the value of shift is one for example (or if it is not given at all) then the first element of the new list is empty or zero, the second is the first of the original list, the third the second of the original and so on.  If shift is set to two, the first two places of the new list are empty, the third is the second of the original list and so on.  If shift is equal to minus one, the last element of the new list is empty, the next to last is the last of the original, and so on.','dl','dl_shift dynlist shift','New list of shifted elements','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(211,'dl_int','command',6,'dl_int','Returns the integer part of a value','When used with a number as argument, dl_int returns the integer part of the number.  When used with a list as argument, the function is applied recursively to each element of the list, and the result is returned in list form.  If the argument contains any string values, then the function will return an error.','dl','dl_int value','Integer or list of integers','dl_float, dl_floor, dl_ceil, dl_round','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(212,'dl_indices','command',6,'dl_indices','Returns indices of non-zero elements of list','When applied to a list of numbers, dl_indices returns a list of the indices of all elements in the list which are not equal to zero.  When applied to a list of lists, dl_indices applies itself recursively to each member list, and returns the result as a list of the same structure.  The original list is left unchanged.  This function will return an error if there are any strings in the argument list hierarchy.','dl','dl_indices num_list','List of same structure of indices','dl_maxIndex, dl_minIndex, dl_maxIndices, dl_minIndices','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(213,'dl_randchoose','command',6,'dl_randchoose','Choose *n* random numbers from between 0 and *m*','This function chooses *m* different integers in the range from 0 to *n*.  It returns the result as a list of integers *n* elements long.  The function will fail if *m* or *n* are not positive integer values, or if *m* is smaller than *n*.  This function differs from the random number generator functions in that it allows finer control over the range (see last example).','dl','dl_randchoose m n','List of random numbers *n* elements long','dl_pickone, dl_randfill, dl_irand, dl_urand, dl_zrand','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(214,'dl_hists','command',6,'dl_hists','Create a list of histograms from a list of numeric lists','This function works in a similar way to dl_hist.  It takes as its arguments a list of lists, the *min*imum and *max*imum values of a numerical range and a number of divisions for the range.   It then runs through each of the lists of lists, counting the number of values in each which fall into each division of the range.  It then returns the result as a list of lists in which each top level element represents a list within the original *lists*, and each of the lists returned contains the number of values from that sub-list in the original *data* which fall within the corresponding interval.  Errors will occur if *min*, *max* or *n* are not numerical values, if *lists* contains strings, or if *n* is negative.','dl','dl_hists lists min max nbins','List of count lists','dl_bins, dl_hist, dl_series','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(215,'dl_sort','command',6,'dl_sort','Sort list elements','For a list of numerical values, dl_sort returns a list built from the same elements as the input list, but reordered from smallest to greatest.  For a list of strings, dl_sort reorders the elements alphabetically.  For a list of lists, the function is applied recursively, and a list is returned in which each element is formed by applying dl_sort to the corresponding element of the input list. In all cases, the return value is the resulting list. dl_sort appears to be identical to dl_bsort (from the code).','dl','dl_sort dynlist','New list','dl_bsort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(216,'dl_acos','command',6,'dl_acos','Return elementwise arc cosine of a list','For lists of numeric values, dl_acos returns a list of the arc cosines, in the range of 0 to pi, of the elements of the  provided list.  For lists of lists, the function is applied recursively.  The returned list is always a list of floats.  NaN is returned for any arguments outside the range [-1,1] if explicit error checking is not on, otherwise an error is returned.','dl','dl_acos list','New list','dl_asin, dl_atan, dl_cos, dl_sin, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(217,'dl_sortByList','command',6,'dl_sortByList','Redistributes the elements of a list amongst several lists','The function dl_sortByList is intended for classifying a list of data by a related list.  It works by redistributing the elements of *dynlist* amongst several other lists.  The list *categs* is a one level deep list of integer indices, which specify which of the returned lists the corresponding elements of *dynlist* should be put into.  If one of the lists is shorter than the other, the extra elements of the longer list will be ignored.  The function will fail if *categs* is of type list, but if they are of type string, the function will assign each a numerical index value (see dl_recode for the assignment method).','dl','dl_sortByList dynlist categs','New list of lists of elements','dl_sortByLists, dl_sortBySelected, dl_sort, dl_bsort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(218,'dl_combine','command',6,'dl_combine','Combine two lists of the same datatype into a new list','dl_combine creates a new list composed of l1 followed by l2. The only constraint is that the two lists are of the same datatype. Note that neither l1 or l2 is changed.','dl','dl_combine l1 l2','New list composed of l1 and l2','dl_collapse, dl_concat, dl_llist, dl_unpack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(219,'dl_filetail','command',6,'dl_filetail','Return the tail of a filename','dl_filetail is used for extracting the tail part - that is to say, stripping off the directory name - from filenames.  It takes as its argument a list of names with paths, and returns a list of the corresponding name tails.','dl','dl_filetail dynlist','New list of file name tails','dl_filebase, dl_filedir, dl_fileext, dl_filetail','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(220,'dl_reset','command',6,'dl_reset','Removes all values from a dynamic list, and sets its length to zero','This function resets a dynamic list, as though it had just been created, by deleting all members of the list, and setting its length to zero.','dl','dl_reset dynlist','','dl_create, dl_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(221,'dl_zeros','command',6,'dl_zeros','Generates lists filled with zeros','This function takes information from the argument list which it uses to build a list of integers full of zeros.  When the function is called with an integer (floats are rounded down to the nearest integer value) as an argument, it returns a list of integers (or floats) of that length made up of zeros.  When called with a list as an argument, it applies itself recursively to each list element and returns the result as a list.  If there are strings in the argument, the call will fail.','dl','dl_zeros size','New list of lists of zeros','dl_ones, dl_not','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(222,'dl_pickone','command',6,'dl_pickone','','dl_pickone is used for choosing a random element from a list of numbers.  It takes a dynamic list as its single argument, and returns an element of that list at random, as a dynamic list of the same type.','dl','dl_pickone `list`','An element of the `list`','dl_randchoose, dl_randfill, dl_irand, dl_urand, dl_zrand','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(223,'dl_pof','command',6,'dl_pof','','','dl','dl_pof f df1 df2','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(224,'dl_sortByLists','command',6,'dl_sortByLists','Redistributes the elements of a list among higher-dimensional arrays','This function is an extension of dl_sortByList which redistributes the members of a list into a multi-dimensional array of lists.  It takes as arguments a list (`dynlist`) of elements to insert into a table, and a set of lists (`categs`) - one for each dimension of the table - which specify the positions where the elements should be inserted.  Each distinct element in a given `categ` list defines an entry into the relevant dimension of the table; the entries are sorted alphabetically.  The returned list contains the contents of the table, merged into a single list.  To see which element of the list corresponds to which position in the table, call the function dl_uniqueCross with the `categ` lists as arguments, or use dl_sortedFunc.','dl','dl_sortByLists dynlist categ(s)','New list of lists into which *dynlist* has been redistributed','dl_sortByName, dl_sortBySelected, dl_uniqueCross, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(225,'dl_return','command',6,'dl_return','Prepares a list to be returned from a procedure','This function prepares a list to be returned from a Tcl procedure.  The importance of this is that if the list to be returned is temporary, this will prevent it from being deleted when the procedure returns.','dl','dl_return dynlist','The name of the return list','dl_clean, dl_cleanReturns','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(226,'dl_pack','command',6,'dl_pack','Create a list of lists from a list','This function turns each element of the source list into a list containing that element.  For scalar lists, each element becomes a list of one element each.  This function can be useful in order to package up a list as an argument to a function like dl_replace which can take as a replacement list, a list of replacement values.','dl','dl_pack list','New list of listed lists','dl_collapse, dl_length, dl_depth, dl_deepPack, dl_deepUnpack, dl_unpack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(227,'dl_filebase','command',6,'dl_filebase','Return the base part of a filename','dl_filebase is used for extracting the base name - that is to say, removing any directory name, and any file extensions - from filenames.  It takes as its argument a list of names, and returns a list of the corresponding basenames.','dl','dl_filebase dynlist','New list of file base names','dl_filedir, dl_fileext, dl_fileroot, dl_filetail','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(228,'dl_last','command',6,'dl_last','Returns the last element in a dynamic list','This function returns the last element of a dynamic list of any type.  If the argument is not a list of lists, then the return value will be a Tcl string, rather than a dynamic list.  If the argument is an empty list, then this function will not return a value.  This function is therefore slow, and should probably be used mainly for debugging, although it is possible to combine it with dl_increment for use as a loop counter.','dl','dl_last dynlist','The last element of *dynlist*','dl_first, dl_get, dl_increment','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(229,'dl_dir','command',6,'dl_dir','Return a list of existing dynlists','The function dl_dir returns a list of all dynamic lists in memory at the time it is called, together with their type, their length and their current memory size.  It returns a Tcl list of lists, with one element for each currently existing variable.  The individual list elements are composed of the following: the list name, which will be in a form like %list1% or %list23% if the list is temporary, or &aul_2& or &choco_4& if the list is local (these could be accessed as $aul and $hoco respectively in a %%\%%dlsh%%\%% command); the data type, one of char, short, long, float, string or list; the number of elements in the list; and the current size of the list, which corresponds to the size of the C language array current ly allocated to hold the list.','dl','dl_dir','List of dynlist descriptions','dl_local, dl_set, dl_clean, dl_cleanReturns','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(230,'dl_weibull','command',6,'dl_weibull','Compute values of the weibull distribution','Compute values of the weibull distribution','dl','dl_weibull x t a b','Value of weibull distribution evaluated at x','dl_gamma, dl_gaussian','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(231,'dl_sortedFunc','command',6,'dl_sortedFunc','Redistribute the elements of a list into a table, and format the result','dl_sortedFunc is based on the dl_sortByLists function.  It takes as arguments `data` and `categ(s)` lists which are identical to those of dl_sortByLists, except that `categ(s)` is given here as a list of lists rather than several lists.  The third argument is a function (dl_means by default) which is applied to the result list of dl_sortByLists.  This is then appended to the result of dl_uniqueCross, with the member lists of `categ(s)` given as arguments to it.  The result may be viewed using dl_dumpMatrix.','dl','dl_sortedFunc data categ(s) func','List of lists containing table indices and elements','dl_sortByLists, dl_selectSortedFunc, dl_uniqueCross','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(232,'dl_sortBySelected','command',6,'dl_sortBySelected','Sort a list using selected values from a set of categorical variables','dl_sortBySelected is a generalized version of dl_sortByLists, but allows for only a subset of the categorical sort variables to be used (the selections).  dl_sortByLists uses the categories themselves to pick the selections, and therefore any category which appears at least once will be used.   dl_sortBySelected allows one to select only certain values from each categorical list to consider.  For example, if two categorical variables were sex (M/F) and age (over 40), then dl_sortByLists with these categories would automatically cross them, to give four output lists: males over forty, males not over forty, females over forty, and females not over forty. dl_sortBySelected would provide a means for only looking at data from females, thus selectively setting aside all cases where gender was male.  The syntax is slightly different from dl_sortByLists, where all arguments after the data list were considered separate categorical variables.  For dl_sortBySelected, the categorical lists are grouped in a tcl list (either with braces or double quotes), and the selection lists are similarly grouped.','dl','dl_sortBySelected list variables selected','List of sorted lists','dl_select, dl_sortByList, dl_sortByLists, dl_uniqueCross','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(233,'dl_fromto','command',6,'dl_fromto','Generate a linear series, but exclude last value','This function is used for generating regular lists of numbers.  It creates a numerical list (of type long if all of the arguments are integer, of type float otherwise) in which the first argument is the *start* value and in which each value is generated by adding *step* to the previous.  The list stops when a value between *stop* minus *step* and *stop* is reached.  If any of the arguments are not scalars (single element numerical lists) or if *stop* is less than *start*, then an error is returned.  If *stop* is equal to *start*, then a one element list consisting of *start* is returned.','dl','dl_fromto start stop [step]','Series of either floats or integers, depending on args','dl_series, dl_bins, dl_fill','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(234,'dl_bmeans','command',6,'dl_bmeans','Take means of lowest level lists maintaining the upper list structure','For a list of numerical values, dl_bmeans returns the mean value of the list as a float.  For a list of lists, the function is applied recursively.  Unlike the functions dl_means and dl_hmeans, dl_bmeans will always preserve the structure of the argument list: the return value will only differ from the original list in that each list or sub-list of numbers will be replaced by a one element float list.','dl','dl_bmeans list','New list','dl_means, dl_hmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(235,'dl_irand','command',6,'dl_irand','Create a list of integer rands from [0,n)','dl_irand returns a list of random ints between 0 and n.  It includes 0 but excludes n.  It is therefore useful for choosing indices, etc.  Unlike dl_randchoose, dl_irand selects random numbers with replacement.','dl','dl_irand size n','List of rands','dl_randchoose, dl_urand, dl_zrand','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(236,'dl_transpose','command',6,'dl_transpose','Transposes the rows and columns of a two-dimensional list array','The function dl_transpose operates on a list of lists of same type and size (lists which are shorter than any other one are filled out with zeros).  It returns a list of as many lists as the child lists  of *dynlist* have elements.  The first of these lists contains the first elements of each of the child lists of *dynlist*; the second list contains the second elements of each child list; the third the third; and so on.  This function will fail if the list structure of *dynlist* does not permit such an operation.  This function is used recursively by functions such as dl_means and dl_stds to redistribute their lists before calculations.','dl','dl_transpose dynlist','List of transposed lists','dl_means, dl_stds, dl_vars, dl_reshape','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(237,'dl_maxIndices','command',6,'dl_maxIndices','Returns indices of maximums of sublists','This function is similar to dl_maxIndex, except that it treats a list of numerical lists in one call.  It finds the highest value in each sublist of the supplied *dynlist* and returns the results as a list of integer values, of the same length as the argument list.  This function is not recursive: if any of the sublists are of type list or string, the function will simply set the result to -1 in the corresponding element of the returned list.  This function will return an error if *dynlist* is not of type list.','dl','dl_maxIndices dynlist','Numerical list of indices','dl_maxIndex, dl_minIndex, dl_minIndices, dl_max, dl_maxs','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(238,'dl_hstds','command',6,'dl_hstds','Return a list of ``horizontal'''' standard deviations for several sets of data','This function operates on a three level deep list of numerical structures.  For it to succeed, the members of the top-level list must be suitable for application of the dl_stds function.  The returned list is then the result of applying dl_stds to each member.  See the descriptions of dl_hmeans and dl_stds for more information.','dl','dl_hstds dynlist','A list of lists of lists of standard deviations','dl_hmeans, dl_hvars, dl_stds, dl_std, dl_bstds','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(239,'dl_and','command',6,'dl_and','Logically combine two lists using AND operation','The dl_and function performs the relational AND operator elementwise on each of the lists.  The result is a list of type long, filled with ones and zeros, representing the result of the and operation. In general, lists of equal numbers of elements will be passed as  arguments.  One of the two arguments can also be a scalar, or a list of only one element (which may be a list).  Lists of strings are not permitted and will return an error.','dl','dl_and list1 list2','A list of 0''s and 1''s resulting from logical AND of list1 and list2','dl_or, dl_not, dl_eq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(240,'dl_mins','command',6,'dl_mins','Returns the minimum of each sublist of a list','This function works similarly to dl_min, but instead of finding the minimum value inside of a single list, it finds the minimum of each of the sublists of a list.  For each of the sublists of *dynlist*, it runs through all numerical values in the list and its sublists to find the highest integer value, and returns the results as a list of integers.  Lists of strings are ignored, and the minimum of an empty list (or one containing only strings) is returned as 0.  This function returns an error if *dynlist* is not of type list.','dl','dl_mins dynlist','List of minimums of lists','dl_maxs, dl_min, dl_max, dl_minIndex, dl_minIndices','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(241,'dl_hmeans','command',6,'dl_hmeans','Return a list of ``horizontal'''' means for several sets of data','This function is an extension of the dl_means function which handles several sets of data in one go.  It takes as its argument a list of numerical lists, and it returns a list of the same length in which each element is obtained by applying the dl_means function to the corresponding element of the source list.  An error will occur if the list elements of the argument list are not suitable for the dl_means function - in particular if they contain string elements, or are not deep enough.  Note that if the lists are incorrectly structured, the dl_means function may partially succeed, in that it returns a list, but one which contains incorrect data, or has the wrong structure.','dl','dl_hmeans dynlist','A list of means','dl_hstds, dl_hvars, dl_means, dl_mean, dl_bmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(242,'dl_llength','command',6,'dl_llength','Returns the length of all numeric and string lists within a list','When applied to a list of numbers, or of strings, dl_llength behaves as dl_length, and returns the number of elements in the list as a Tcl integer value.  When applied, however, to a list of lists, dl_llength returns a list of the same length, the elements of which are obtained by recursive application of dl_llength to the corresponding element of the original list.  Curiously, a list containing a single list is treated as though it were that single list (see example).  The original list is always left unchanged.','dl','dl_llength dynlist','List of lengths','dl_length, dl_lengths','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(243,'dl_repeatElements','command',6,'dl_repeatElements','Repeat each non-list element of a list','dl_repeatElements is similar to dl_repeat, except in the way in which lists of lists are repeated.  dl_repeat treats the source list as a single lists and applies the repeat values to each element of the top level list.  dl_repeatElements will not repeat lists, and instead recursively call itself until a list of scalars is found.  At that point, dl_repeat is applied.','dl','dl_repeatElements source repeats','Newly created repeat list','dl_choose, dl_repeat, dl_replicate','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(244,'dl_pushTemps','command',6,'dl_pushTemps','Remembers the state of existing temporary lists','This function makes a note of which temporary lists exist at the time it is called, and keeps this information until the dl_popTemps function is next called, at which time it deletes all temporary lists other than the ones it has kept track of.  If dl_pushTemps is called several times, then it will make several records of temporary lists existing, and each call to dl_popTemps will work with (and then throw out) the last record taken down.  For more detailed information, see the section on dl_popTemps.','dl','dl_pushTemps','','dl_popTemps, dl_clean','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(245,'dl_select','command',6,'dl_select','Selects elements from a list','This function enables the selection of values from a dynamic list.  The *indices* argument, used to specify which elements from *dynlist* one wishes to select, may be a list of boolean values, or (if it contains values other than one and nought) a numerical list of indices.  In the second case, the function acts like dl_choose, and in this case, dl_choose should probably be used in place of dl_select to avoid possible ambiguity.  In the first case, if the list *indices* contains a single value of one or nought, it specifies whether to return or not (respectively) *dynlist* as a whole.  If it is a list of ones and noughts and lists, each is applied to the corresponding element of *dynlist* and the result is returned as a list of the same type as *dynlist*.  The call will fail if *indices* is not a list of integers, or if it is of type boolean, with an element count greater than one and different to that of *dynlist*.','dl','dl_select dynlist indices','New list of selected values','dl_choose, dl_find, dl_replace','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(246,'dl_urand','command',6,'dl_urand','Returns lists of random numbers between nought and one','This function returns a list of lists of random numbers between nought and one.  The number returned is given by the *size* argument.  If this is a list of length greater than one, the return value will be a list of lists of that length, where each member of the size list gives the length of the corresponding return list.  If it is a list of more levels of depth, the function will be applied recursively, and the result returned as a list.  If *size* is just one element long, it specifies the number of random numbers which should be returned.  The function will fail if called with a string argument, but will consider float values as equal to the next lowest integer.  The main difference between this and the dl_irand and dl_zrand functions is the range of the return value.','dl','dl_urand size','New list of lists of random numbers','dl_irand, dl_zrand, dl_randchoose','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(247,'dl_clean','command',6,'dl_clean','Delete temporary lists that are no longer needed','dl_clean deletes temporary lists that have been created during the current session.  Whenever a dl_function is called without explicitly setting a dynlist with dl_set or without adding the dynlist to a dyngroup, a temporary list is created (with the name %list..%).  These lists are referred to as anonymous lists, because they allow operations to be chained, even though their name is never actually saved.  After extensive computations, these unnamed anonymous lists can consume considerable memory, so it is wise to call dl_clean to remove them.','dl','dl_clean','None','dl_cleanReturns, dl_delete','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(248,'dl_length','command',6,'dl_length','Gives the length of a dynamic list','dl_length counts the elements in a dynamic list, and returns the result as a Tcl integer value.','dl','dl_length dynlist','Length of *dynlist*','dl_lengths, dl_llength, dl_count, dl_counts, dl_lcounts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(249,'dl_exists','command',6,'dl_exists','Test whether a dynamic list exists','The dl_exists function takes as its argument a name which might belong to a dynamic list, as a Tcl string, and returns the value 1 if the list exists or 0 if it does not, again as a Tcl string.','dl','dl_exists name','1 if the list exists, 0 otherwise','dl_create','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(250,'dl_abs','command',6,'dl_abs','Return element-wise absolute value of a list','For lists of numeric values, dl_abs returns a list of the absolute value of the elements of the provided list.  For lists of lists, the function is applied recursively.  The datatype is preserved, since there is no need to promote integers for this operation.','dl','dl_abs list','New list','dl_floor, dl_ceil','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(251,'dl_var','command',6,'dl_var','Returns the variance of a list','When applied to a single list of numbers, this function returns the variance of the list as a Tcl floating point value.  When applied to a list of strings, dl_std returns an error.','dl','dl_var dynlist','Tcl floating point value of variance','dl_vars, dl_bvars, dl_hvars, dl_std, dl_stds','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(252,'dl_atan','command',6,'dl_atan','Take the elementwise arctan of a list','For lists of numeric values, dl_atan returns a list of the arc tangents, in the range of -pi/2 to pi/2, of the elements of the  provided list.  For lists of lists, the function is  applied recursively.  The returned list is always a list of floats.','dl','dl_asin list','New list of arctan transformed values','dl_acos, dl_asin, dl_cos, dl_sin, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(253,'dl_sin','command',6,'dl_sin','Returns the sine of a list','dl_sin takes as its argument a dynamic list of numbers.  It returns a list which is identical to the argument, except that each value in the argument is replaced in the return list by its sine.  The function will fail if the argument list contains any elements other than numbers and lists.','dl','dl_sign dynlist','New float list of sines of *dynlist*','dl_cos, dl_tan, dl_sinh, dl_asin','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(254,'dl_sem','command',6,'dl_sem','Returns the standard error of the mean of a list of numbers','When applied to a single list of numbers, this function returns the standard error of the mean of the list as a Tcl floating point value.  When applied to a list of strings, dl_std returns an error.','dl','dl_sem dynlist','Tcl floating point value of standard deviation','dl_stds, dl_bstds, dl_hstds, dl_var, dl_vars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(255,'dl_gaussian','command',6,'dl_gaussian','Returns a value from a Gaussian curve','This function returns the value of the Gaussian curve described by the parameters at the point *x*.  The value returned is given by the formula ( e^{-(%%\%%frac{x-mean}{sd})^{amp}} ) One or several sets of parameters may be specified, with a complex list structure.','dl','dl_gaussian x amp mean sd','Tcl value or new list, value of Gaussian curve at offset *x*','dl_gamma, dl_weibull','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(256,'dl_count','command',6,'dl_count','Count the number of elements in a list falling within a range','This function counts the values in *list* and all its sublists  which are greater than or equal to *min*, but strictly less than *max*.  It differs from dl_counts and dl_lcounts in that it returns a single integer value.  Note that it may also be used to check whether a scalar falls inside a particular range (see examples).','dl','dl_count list low high','Integer number of values','dl_counts, dl_lcounts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(257,'dl_uniqueNoSort','command',6,'dl_uniqueNoSort','Removes removes from a list elements identical to the ones before','This function runs through a list of numbers or of strings and returns a list which is identical except that all values identical to the previous ones have been removed.  This function is the basis of the dl_unique function, which first sorts a list, then removes duplicate values.  The function will fail if it is called with a list of lists as argument.','dl','dl_uniqueNoSort dynlist','New list of integers or strings, without duplicated elements','dl_unique, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(258,'dl_cross','command',6,'dl_cross','Create a complete crosswise set of the elements of all lists specified','This function operates on several lists of same data type, and returns lists representing the possible combinations of one element of each argument list.  The number of lists returned will be the same as the number supplied, and the length of each list will be equal to the product of the lengths of each argument list.  The possible unique combinations of elements are given by the list cross sections; the combinations may be extracted using dl_choose with a two level deep list of indices. This function can serve to analyse the frequency of a particular combination by transposing the list of lists (dl_transpose) and counting the appearances with  dl_countOccurences.','dl','dl_cross list0 list1 … listn','New list of unique combinations of all elements of all lists','dl_uniqueCross, dl_sortByLists','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(259,'dl_recode','command',6,'dl_recode','Returns the size order of each member of a list','This function runs through a list of numbers or of strings ranking the values from smallest to greatest - numerically or alphabetically respectively - and returns a list of the same length as the argument in which each member is the previously found rank of the corresponding element within the argument list.  *dynlist* must not contain any elements of type list, or the call to the function will fail.','dl','dl_recode dynlist','New list of orders','dl_sort, dl_indices, dl_index','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(260,'dl_conv','command',6,'dl_conv','Convolve an input vector with another vector','dl_conv convolves the input data with the specified kernel by sliding the kernel across every input point and doing a componentwise multiply and add.  The convolution is not done in the Fourier domain, so this algorithm is not efficient for extremely large kernels.','dl','dl_conv data kernel','The convolved list','dl_mult, dl_sdf, dl_sdfs','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(261,'dl_put','command',6,'dl_put','Replaces a value within a dynamic list','This function replaces the *index*-th member of the dynamic list *dynlist* by the value *newval*.  The *index* must be that of a member of the list (the first element is at index 0), and *newval* must be of a type compatible with *dynlist*.','dl','dl_put dynlist index newval','New value of *dynlist*','dl_get, dl_insert, dl_append, dl_prepend','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(262,'dl_gt','command',6,'dl_gt','Compare elements of arg1 and arg2 using greater than relation','When applied to two scalar values, dl_gt will return 1 if the first is greater than the second, and 0 otherwise.  If applied to two strings, dl_gt will return 1 if the first string comes alphabetically later than the second.  If applied to two identical lists, dl_gt will return a list in which the n-th element is obtained by recursive application to the n-th elements of the first and second lists. If one argument is a list, and the other a single element, that element will be compared to each element in the list, and the result returned as a list. In the first two cases, the return value will be a list of type long, in the third and forth a list of type list.  If the two arguments are of different types, and neither is a list, an error will result.  Similarly, if the two arguments are lists of several elements, they must be of the same length, or an error will result.','dl','dl_gt arg1 arg2','List of (lists of) boolean values','dl_gte, dl_lt, dl_lte, dl_eq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(263,'dl_minIndex','command',6,'dl_minIndex','Returns the index of the minimum of a list','This function, applied to a list of numeric or float type, returns the index of the minimum of the list as a Tcl integer value.  If the list *dynlist* is of type list, or string, an error will result: this function is not recursive.  Note that the first list element has index 0.','dl','dl_minIndex dynlist','Index of list minimum','dl_minIndices, dl_maxIndex, dl_maxIndices, dl_min, dl_mins','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(264,'dl_poz','command',6,'dl_poz','','','dl','dl_poz f df1 df2','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(265,'dl_replicate','command',6,'dl_replicate','Replicate an entire list multiple times','This function takes a list as its argument, and returns a new list formed by duplicating *dynlist* and then appending it *count* minus one times to the end of the duplicate list. *count* must be a positive integer value (negative values are treated as zero) or the function will fail.','dl','dl_replicate dynlist count','New list of same type as *dynlist* of replicated values','dl_repeat','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(266,'dl_cos','command',6,'dl_cos','Take the elementwise cosine of a list','dl_cos computes the cosine for each element of a list and returns a new dynlist containing the results.','dl','dl_cos list','New list of cosine transformed values','dl_acos, dl_asin, dl_atan, dl_cosh, dl_sin, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(267,'dl_replaceByIndex','command',6,'dl_replaceByIndex','Replace elements of a list with substitute elements using indices','The dl_replaceByIndex replaces selected elements of a source list using index selection, as opposed to the logical selection used by dl_replace.','dl','dl_replaceByIndex list selections replacement(s)','New list of substituted list','dl_choose, dl_find, dl_replace, dl_select','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(268,'dl_maxs','command',6,'dl_maxs','Returns the maximum of each sublist of a list','This function works similarly to dl_max, but instead of finding the maximum value inside of a single list, it finds the maximum of each of the sublists of a list.  For each of the sublists of * dynlist*, it runs through all numerical values in the list and its sublists to find the highest integer value, and returns the results as a list of integers.  Lists of strings are ignored, and the maximum of an empty list (or one containing only strings) is returned as 0.  This function returns an error if *dynlist* is not of type list.','dl','dl_maxs dynlist','List of maximums of lists','dl_mins, dl_max, dl_min, dl_maxIndex, dl_maxIndices','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(269,'dl_ones','command',6,'dl_ones','Returns a list made up of ones.','This function returns a dynamic list of similar structure to the supplied list *size* which in the place of every numerical value in the list *size* (rounded down, if necessary, to an integer) returns a list of the same type containing that many ones.  The function will fail if the list contains any string values, or any negative values.  The argument list is not changed.','dl','dl_ones size','A list of ones, of similar structure to *size*','dl_zeros, dl_not','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(270,'dl_local','command',6,'dl_local','Create a locally scoped dynlist','The dl_local function provides a method for creating local dynlists that are protected from dl_clean, but that are also deleted when a the calling procedure is exited.  The first argument is a variable name which is set inside the dl_local function.  Note that access to the local list will generally require the $arname notation, in contrast to lists created with dl_set, which are globally scoped. An important feature of dl_local is that both the new variable and the dynamic list associated with the variable are automatically deleted when the calling procedure is exited (or the variable is explicitly unset).  Another feature is that unlike the call to dl_set, using dl_local to rename a list within a dynamic group will not remove the original list from the group. The dl_local proc is preferred to dl_set in almost all circumstances with a couple of notable exceptions.  When a list is to be added to an existing dynamic group, it is very common to set the new list using the dl_set function. Also, because the dl_local function cleans up after itself, dl_set can be used for basic debugging when a list needs to be created that can exist after  a local function returns.','dl','dl_local varname list','The name of the new list','dl_set','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(271,'dl_cumsum','command',6,'dl_cumsum','Compute the cumulative sums of a list','This function outputs a numerical list in which the n-th element is formed by adding the previous element output to the n-th element of the input list.  The first element output is the first element of the input list.','dl','dl_cumsum list','New list of cumulative sums','dl_cumprod, dl_sum, dl_sums','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(272,'dl_sign','command',6,'dl_sign','Returns the sign of the members of a list','This function returns a dynamic list of type integer, identical in structure to the argument *dynlist*, but in which each number in *dynlist* is replaced by a 1 if it is greater than zero, by 0 if it is equal to zero, and by -1 if it is less than zero.  The function will fail if the list *dynlist* contains elements other than numbers and lists.','dl','dl_sign dynlist','New integer list of signs of elements of *dynlist*','dl_abs, dl_ceil, dl_floor','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(273,'dl_floor','command',6,'dl_floor','Round each value of a list to the next lower (or equal) int','When applied to a list of floating point or integer values, this function rounds them down to the nearest integer value, leaving values which are already integer untouched, and returns the result as a list of integers.  When applied to a list of lists, this function applies itself recursively to each sublist, and returns the resulting list.  In all cases, the original list is left unchanged.  If this function is applied to a list of strings, an error will result.  This function seems in practice to be identical to dl_int.','dl','dl_floor list','List of integers corresponding to floor of the values list','dl_ceil, dl_int, dl_round','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(274,'dl_ilist','command',6,'dl_ilist','Create a new integer dynlist','dl_ilist is simply a procedure that calls dl_create with the int option.  Like dl_create, it accepts optional args to add to the new list.','dl','dl_ilist [i0 … in]','Name of new integer list','dl_create, dl_clist, dl_flist, dl_llist, dl_slist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(275,'dl_stds','command',6,'dl_stds','Calculates the standard deviations of variables over several lists','This function works on a list of lists, returning a list of lists of the same size.  It operates on the members of the sub-lists of the top-level list, which must be numbers, or numerical lists of identical structure.  In the return value of the function, these  elements are replaced by a list of floats of the same structure, in which each element is the standard deviation of the corresponding elements in the original lists.  A practical example of this might be a process in which several data sources were sampled simultaneously, and the results stored in a list data structure.  If the results of several samplings were stored within a list within a list, and the function dl_stds then applied, the resulting list within a list would contain a list data structure holding the standard deviations of all experimental variables.  The function will fail if *dynlist* contains string elements, or if the list structure is not suitable for the function.','dl','dl_stds dynlist','New list of lists of standard deviations','dl_sem, dl_sems, dl_semList, dl_means, dl_vars, dl_std, dl_hstds, dl_bstds','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(276,'dl_regexp','command',6,'dl_regexp','Returns logical vector for matches using regular expressions','Returns logical vector for matches using regular expressions','dl','dl_regexp ?options? dynlist regexp','List of matched strings/substrings','dl_stringmatch, dl_regmatch','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(277,'dl_isMatrix','command',6,'dl_isMatrix','Tests whether a list is a matrix','The function dl_isMatrix tests to see whether its argument is valid for use within %%\%%dlsh ''s matrix functions.  For a list to be a valid matrix, it must be a list of lists of floating point values.  The return value is a Tcl string: 1 if the argument is a matrix, 0 otherwise.','dl','dl_isMatrix dynlist','1 if a matrix, 0 otherwise','dl_transpose, dl_reshape, dm_functions','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(278,'dl_append','command',6,'dl_append','Append an element onto the end of a list','The dl_append function is a primitive function for appending elements to a list.  It is generally called when functions not supported directed by dl_functions must be performed in tcl and then appended to a dynlist one at a time.  This function should be used only as a last resort, because it is generally used in the context of a slow tcl-based loop structure. Over-dependence on dl_append indicates that the vectorized dl_functions, which can be up to two orders of magnitude faster than equivalent interpreted tcl functions, are not being  fully utilized.','dl','dl_append list element','The appended list','dl_concat, dl_create, dl_set','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(279,'dl_div','command',6,'dl_div','Divide one list by another','If dl_div is executed with a scalar value as its first argument, and a scalar, or a list of scalars as its second, it will return a list of scalars obtained by dividing the first argument by each value from the list.  If it is executed with a scalar value as its second argument, and a list of scalars as its first, the return value will be formed by dividing each of the elements of the first list by the second argument.  If either of the arguments are floats, the return value will be a float.  If instead of a list of scalars, a list of lists is given, the function will be applied recursively to each element of the list, with the same scalar argument.  Finally, if both arguments are lists of similar structure, the function will return a list in which the n-th element is formed by recursive application on the n-th elements from the first and second lists.','dl','dl_div arg1 arg2','New list containing arg1/arg2','dl_mod, dl_mult, dl_add, dl_sub','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(280,'dl_medians','command',6,'dl_medians','Returns the median value of each element of a list','This function returns the median value of each sublist of a list as a new list.  The sublists must be of type float, or an error will occur.','dl','dl_medians dynlist','New list of floats, containing medians of arguments','dl_median, dl_means, dl_sort','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(281,'dl_tempname, dl_tmpname','command',6,'dl_tempname, dl_tmpname','Returns a temporary file name','This function returns a filename which may be used for the creation of a new temporary file.  At the time that the function is called, no file of the given name will exist; for extra safety, you should create the temporary file non-destructively, for instance using%%\%% *%%\%%prompt open [dl_tempname] RDWR CREAT EXCL* %%\%% Note that the *-dir* option is not really safe to use, since it could cause problems in the event of a port of %%\%%dlsh to other operating systems.','dl','dl_tempname [-prefix prefix] [-dir dir]','Tcl string, temporary filename','dl_dump','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(282,'dl_maxIndex','command',6,'dl_maxIndex','Returns the index of the maximum of a list','This function, applied to a list of numeric or float type, returns the index of the maximum of the list as a Tcl integer value.  If the list *dynlist* is of type list, or string, an error will result: this function is not recursive.  Note that the first list element has index 0.','dl','dl_maxIndex dynlist','Index of list maximum','dl_maxIndices, dl_minIndex, dl_minIndices, dl_max, dl_maxs','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(283,'dl_lte','command',6,'dl_lte','Compares two lists using `less than or equal to`operator','This function is analogous to dl_lt, except that it uses the `less than or equal to` operator in the  place of `less than`.','dl','dl_lte list1 list2','List of results of comparisons','dl_lt, dl_gt, dl_gte, dl_eq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(284,'dl_add','command',6,'dl_add','Add two lists together','The dl_add function performs elementwise additions between two lists, or between a scalar value and a list.  In the latter case, the scalar is added to all elements of the list argument.  For lists of lists, the function is applied recursively. It is possible to add two scalars, but the result will still be a list one element long, so the Tcl *expr* function is probably a better method for doing such a numeric calculation. Types are preserved if the two arguments are of the same data type.  In other cases, if both types are integral, a list of longs is returned.  If either argument contains floats, the returned list is promoted to type float.  Lists of unequal lengths, except for the case of a single element list – which is treated like a  scalar, cannot be added and will result in an error.','dl','dl_add arg1 arg2','New list of sums','dl_sub, dl_mult, dl_div, dl_sum, dl_sums, dl_zeros','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(285,'dl_recip','command',6,'dl_recip','Returns the reciprocal of a list','Applied to a list of numbers, dl_recip returns a list of identical structure, but one in which each numerical value is equal to 1 divided by the corresponding value in *dynlist*.  An error will be returned if the list contains any strings.','dl','dl_recip dynlist','New list of reciprocals','dl_div, dl_negate','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(286,'dl_bstds','command',6,'dl_bstds','Take stds of lowest level lists maintaining the upper list structure','The function dl_bstds is used for calculating standard deviations of numerical lists.  When applied to a list of numbers, it will return the standard deviation of the list elements as a scalar, treated as a one element list of floats.  When applied to a list of lists however, it will return a duplicate of the list, in which all numerical lists within the list structure are replaced by their standard deviation.  If the list tree contains any lists of strings, they will be replaced by the floating point value 0.  This function differs from the dl_hstds and dl_stds functions in that it preserves the list structure of the input.','dl','dl_bstds list','New list','dl_stds, dl_hstds, dl_bmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(287,'dl_min','command',6,'dl_min','Returns the minimum value of a list','This function runs through the supplied list *dynlist* and returns the highest numerical value which it finds, as a Tcl integer. The list may have several levels.  Any string values found will be ignored.  If several argument lists of similar structure are supplied, dl_min will return a single new list of such a structure.  Each element of this new list will be the minimum of the corresponding elements in the argument lists; this means that if dl_min is called with three lists of five integers, it will return a list of five integers in which the first element is the minimum of the first elements of each argument list, the second the minimum of the second elements and so on.  If it is called with two lists of five and a single number, the number will be treated as a list of five times itself.  If any of the argument lists contain floats, the returned list will contain floating point values.','dl','dl_min dynlist','The minimum of *dynlist*','dl_mins, dl_max, dl_maxs, dl_minIndex, dl_minIndices','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(288,'dl_prods','command',6,'dl_prods','Returns the products of each member of a list of lists','This function calculates the product of each member of the argument list, returning the results as a new list.  These members may be lists of numbers, or more complex lists, in which case the function calculates the product of all numerical values within the list, or gives back an empty list if there are none.  The call will fail if the argument is not a list of lists.  Note that the product of a list of lists containing no numbers is defined to 1, that of a list of strings on its own to 0.','dl','dl_prods dynlist','New list of numbers, products of elements of *dynlist*','dl_prod, dl_mult, dl_cumprod','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(289,'dl_lowess','command',6,'dl_lowess','Smoothes scatterplot data using LOWESS algorithm','This function smoothes curve data for plotting using Cleveland''s robust locally weighted regression algorithm, which can be used to try to compensate for the effects of measurement error in a set of plot data.  A precise description of the algorithm is included with the library source code.  The *delta* parameter is used for saving computations, and should be left at 0.0 for values of *nsteps* less than 100.  For values greater than 100, you should consult the algorithm documentation.','dl','dl_lowess x_list y_list [f nsteps delta]','List of y co-ordinates of smoothed curve','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(290,'dl_lcounts','command',6,'dl_lcounts','Count elements of single lists (preserving list structure)','This function returns a dynamic list which is built from the original list in the following way: if an element of the argument list is a list of lists, the corresponding element of the return list is the result of applying dl_lcounts recursively to that element.  If the element is not a list of lists, the return list element will be obtained by application of dl_count in the place of dl_lcounts.  In other words, it returns a list of the same structure as *dynlist* in which each numerical list is replaced by the count of elements which it contains, greater than or equal to *tt low*, but strictly less than *high*.  This function will fail if it is applied to a list containing strings, or a list of type other than list. If the low and high values are themselves lists, then these represent multiple ranges and the function will be applied for each range such that the resulting list will be the same length as the length of the low and high lists (which must be the same length as each other).','dl','dl_lcounts dynlist low high','A list of count lists','dl_count, dl_countOccurences, dl_counts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(291,'dl_lt','command',6,'dl_lt','Compares two lists using ``less than'''' operator','The dl_lt function applied to a list as first argument and a single value as second will return a list of similar structure in which the list elements are replaced by one if they are less than the single value, and by zero otherwise.  For strings, the comparison is alphabetic.  Applied to a single value as first argument and a list as second, the function works analogously, but returning one if the value is less than the list element.  Similarly between two scalars, treated as one element lists.  Finally, applied to two lists of equal length, the function returns a list formed by applying itself recursively to corresponding values of both argument lists.  If applied to two lists of different length, or of incompatible type, the function returns an error.  If one of the arguments is empty, no value will be returned.','dl','dl_lt list1 list2','List of boolean values','dl_lte, dl_gt, dl_gte, dl_eq','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(292,'dl_sems','command',6,'dl_sems','Returns the standard error of the mean for a list of lists of numbers','This function returns a list of	standard errors of the mean for each sublist.','dl','dl_sems dynlist','New list of sems for each list','dl_sem, dl_semList, dl_stds, dl_bstds, dl_hstds, dl_var, dl_vars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(293,'dl_datatype','command',6,'dl_datatype','Return the datatype of a list','This function returns the list type of the argument as a Tcl string.   It does not take into account sub-lists for lists of lists.  This function could be used for debugging, or for error checking dynamic lists used as arguments to functions.','dl','dl_datatype list','Name of the datatype (char, short, long, float, string, list)','dl_create, dl_dump, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(294,'dl_lsfit','command',6,'dl_lsfit','','','dl','dl_lsfit x y','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(295,'dl_hist','command',6,'dl_hist','Create a frequency histogram for a list of data','This function creates a frequency histogram for the *data* supplied as first argument.  It works by creating a list of *n* integers representing a division of the range between *min* inclusive and *max* exclusive into *n* regular intervals, and sets each value in the return list to the number of values from the *data* which fall within the corresponding interval.  If data is a list of lists, then the function will run through each of the lists and its sub-lists. This function will return an error *data* contains strings, or if *min*, *max* or *n* are not positive integers. If *min* is greater than *max*, then the returned list will be all zeros.  Note that this function may be used together with dl_bins to graphically plot histograms.','dl','dl_hist data min max nbins','List of counts','dl_bins, dl_hists, dl_series, dlp_plotting_functions','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(296,'dl_increment','command',6,'dl_increment','Increment and append the last value in a dynamic list','This function alters the source list of integers in one of two ways.  If no second argument is specified, it appends a new value to the end of the source list which is one greater than the current last val.  If a position argument is supplied, the value at that index is incremented.','dl','dl_increment numbers [position]','changed list','dl_last, dl_append','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(297,'dl_selectSortedFunc','command',6,'dl_selectSortedFunc','Redistribute the elements of a list into a table, and format the result','dl_selectSortedFunc is similar to dl_sortedFunc, but is based on dl_sortBySelected, rather than dl_sortByLists.  What this means is that it filters out all elements of the `categ(s)` list which are not also in the `selection(s)` list, together with the corresponding elements of the `data` list.','dl','dl_selectSortedFunc data categ(s) selection(s) func','List of lists containing table indices and elements','dl_sortBySelected, dl_sortedFunc, dl_uniqueCross','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(298,'dl_filedir','command',6,'dl_filedir','Return the directory part of a filename','dl_filedir is used for extracting the directory name - that is to say, removing any main parts and extensions - from filenames.  It takes as its argument a list of names, and returns a list of the corresponding directory names.','dl','dl_filedir dynlist','New list of file base names','dl_filebase, dl_fileext, dl_fileroot, dl_filetail','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(299,'dl_dumpMatrixInCols','command',6,'dl_dumpMatrixInCols','Dump the values of a two-dimensional list in columns','This function is similar to dl_dumpMatrix, but its output is transposed relative to dl_dumpMatrix along the main diagonal, and it fills spaces in the matrix table  with asterisks.','dl','dl_dumpMatrixInCols list [fileid]','None','dl_dumpMatrix, dl_dump, dl_setFormat, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(300,'dl_counts','command',6,'dl_counts','The dl_count function applied to a list','The dl_counts function acts on the elements of a list in the same way that dl_count acts on a whole list - it counts the number of sub-elements (or elements of lower level lists) which are greater than or equal to *min* but strictly less than *max*, and returns the result as a list, containing one element for each element of the original list.  Unlike dl_lcounts, dl_counts does not return a list which reflects the original list structure.','dl','dl_counts list low high','A list of counts','dl_count, dl_lcounts','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(301,'dl_dumpMatrix','command',6,'dl_dumpMatrix','Dump the values of a two-dimensional list row by row','This function writes to the terminal or to an open file the contents of a list of lists.  The format used is a combination of that of dl_dump and dl_dumpAsRow - each sublist of the list is displayed on a row with its contents in columns.  The call will fail if {%%\%%tt fileid} is given, but does is not the Tcl identifier of an open file.','dl','dl_dumpMatrix list [fileid]','None','dl_dump, dl_dumpMatrixInCols, dl_setFormat, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(302,'dl_cycle','command',6,'dl_cycle','Shift all elements of a list cyclically','dl_cycle moves all elements of a list rightward (positive shift) or leftward (negative shift) and cycles the elements from the end of the list to the beginning and vice versa.  For shifts without cycling, use dl_shift and dl_shift. If the shifter argument is not specified, it defaults to 1.','dl','dl_cycle list [shifter]','New list of cycled elements','dl_permute, dl_shift','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(303,'dl_ceil','command',6,'dl_ceil','Round each value of a list to the next higher value',replace('dl_ceil rounds up each element of its input list to the next\nhigher integer if the element is fractional or to itself if the\nelement is integral.','\n',char(10)),'dl','dl_ceil list','List of integers corresponding to ceil of the values list','dl_floor, dl_float, dl_int, dl_round','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(304,'dl_transposeAt','command',6,'dl_transposeAt','Transposes the rows and columns of a multi-dimensional list array at a given level','The function dl_transposeAt operates very similarly to dl_transpose except it can transpose sublists if the depth argument is >0.','dl','dl_transpose dynlist depth','List of transposed lists','dl_means, dl_transpose, dl_vars, dl_reshape','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(305,'dl_cumprod','command',6,'dl_cumprod','Compute the cumulative products of a list','dl_cumprod outputs a numerical list in which the n-th element is formed by taking the product of the previous element of the output list by the n-th element of the input list.  The first element output is the first element of the input.','dl','dl_cumprod list','New list of cumulative products','dl_cumsum, dl_prod, dl_prods','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(306,'dl_sortIndices','command',6,'dl_sortIndices','Gives the indices of list elements, sorted by order of elements','When applied to a list of numbers, dl_sortIndices returns a list of integers of the same length, in which the first element is the index of the smallest value in the list, the second the index of the second smallest and so on.  Applied to a list of strings, the function works in a similar way, but the sorting is done by alphabetical, not numerical order.  Finally, when applied to a list of lists,  dl_sortIndices applies itself recursively to each list element, and returns the results as a list of lists.','dl','dl_sortIndices dynlist','Sorted indices of list elements','dl_sort, dl_bsort, dl_recode','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(307,'dl_delete','command',6,'dl_delete','Delete an existing list','This command deletes a dynamic list which is no longer needed.  This is advisable to prevent lists which have previously been used as command arguments from unnecessarily consuming system memory.  Note that although it improves programme readability, creating and later deleting variables is slow, due to the time necessary to process the commands.  Use of the dl_local command can provide a compromise, since local lists are deleted when the command returns.','dl','dl_delete list','None','dl_create, dl_set, dl_local, dl_clean, dl_cleanReturns','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(308,'dl_means','command',6,'dl_means','Calculates the horizontal mean values of several lists','This function operates on a list of numerical lists.  The same - rather complex - operation will be performed on each of the members of *dynlist*, and the results will be returned as a list.  I will take the member list *sub1* as an example to explain the operation performed.  Firstly, each of the members of *sub1* must be of identical list structure, containing no lists of strings or empty lists.  If any one of the sublists contains a numerical list shorter than the corresponding list in one of the other sublists, the shorter list will be padded out with zeros.  The list returned will be of the same structure as the sublists of *sub1*, with each numerical value the mean of the corresponding values in the sublists of *sub1*.  This function is useful for normalising lists by dividing by the mean value (see last example).','dl','dl_means dynlist','List of horizontal mean values of lists','dl_mean, dl_hmeans, dl_bmeans','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(309,'dl_cosh','command',6,'dl_cosh','Take the elementwise hyperbolic cosine of a list','dl_cosh computes the hyperbolic cos for each element in its input list and returns a new float dynlist of the results.','dl','dl_cosh list','New list of hyperbolic cosine transformed values','dl_acos, dl_asin, dl_atan, dl_cos, dl_sin, dl_tan','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(310,'dl_sub','command',6,'dl_sub','Subtracts one dynamic list from another','When applied to a list and a scalar, this function subtracts the returns a list containing the original list values with the scalar value subtracted from each.  When applied to a scalar and a list, the function returns a list containing the results of subtracting each list value from the scalar.  Finally when applied to two lists of the same length, the function is applied recursively to each corresponding pair of elements from the two lists, and the result is returned as a list.  The function will fail if it is applied to lists containing string elements, or to two lists of different lengths.','dl','dl_sub list1 list2','New list of numbers containing difference of two lists','dl_add, dl_mult, dl_div, dl_diff','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(311,'dl_dump','command',6,'dl_dump','Dump the values of a list, as a column, to screen or open file','This function prints out the contents of a dynamic list as text, either to the screen (mainly for debugging purposes) or to a file, specified by the Tcl file identifier *fileid*.  This may be used for quickly constructing ASCII data files, or automatically generating text files.  The function will fail if *fileid* is given, but does not refer to an open file.  Note that lists of lists will be printed out in the form ``{%%\%%tt List(m,n)}'''' where m is the integer element type identifier, and n the number of elements.  Note also that the format of the output can be modified using dl_setFormat.','dl','dl_dump list [fileid]','None','dl_setFormat, dl_tcllist, dl_dumpAsRow, dl_tempname','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(312,'dl_diff','command',6,'dl_diff','Compute the lagged difference between elements of a list','When applied to numerical list without a *lag* value, or with a *lag* value of one, dl_diff subtracts each list element from the next, and returns the result as a list one element shorter than the original.  If it is applied with a lag value of two, each list element will be subtracted not from the next, but from the next but one, and the returned list will be two elements shorter than the original.  Similarly, with a *lag* of three, subtraction will be from the next but two and so on.  If the *lag* value is zero, each list element will be subtracted from itself, and so a list of the same length, but of zeros will be returned.  *lag* values less than zero will not return an error, but the first entries (the first two for a *lag* of -2) will be undefined.  If *lag* is greater than the length of the list, an empty list will be returned.  The data type of the list is preserved; the data type of the lag value must be integer, or an error will occur.  When dl_diff is applied to a list of lists, the return value will be obtained by applying the function recursively to each sub-list.  An error will occur if the input is a list of strings.','dl','dl_diff list [lag]','List of differences containing *lag* less than the number of  elements of list.','dl_sub, dl_add, dl_sum, dl_sums, dl_mult, dl_div','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(313,'dl_critf','command',6,'dl_critf','Compute critical F value to produce given probability','This function is borrowed from code written by Gary Perlman  of the Wang Institute. Begin with upper and lower limits for F values (maxf and minf – internal to the actual c-code) set to extremes.  Choose an f value (fval) between the extremes. Compute the probability of the f value.  Set minf or maxf, based on whether the probability is less than or greater than the desired p.  Continue adjusting the extremes until they are within F_EPSILON of each other. To use the function in place of a table, one would first choose the probability of interest (such as 0.95) and then  $%%\%%alpha = (1.0-.095) = 0.05$ with the appropriate degrees of freedom.','dl','dl_critf alpha df1 df2','a list of one or more critical f values','dl_pof, dl_critz, dl_poz','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(314,'dl_std','command',6,'dl_std','Returns the standard deviation of a list','When applied to a single list of numbers, this function returns the standard deviation of the list as a Tcl floating point value.  When applied to a list of strings, dl_std returns an error.','dl','dl_std dynlist','Tcl floating point value of standard deviation','dl_sem, dl_sems, dl_semList, dl_stds, dl_bstds, dl_hstds, dl_var, dl_vars','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(315,'dl_first','command',6,'dl_first','Returns first element of a list',replace('This function will return the first element of a dynamic list.  The\nvalue returned will be of the same type as the list elements.  Note\nthat if the argument is not a list of lists, it will be returned as\na Tcl list, rather than as a dynamic list.  Therefore, this function\nis particularly slow, and probably best reserved for debugging.  If\nthe argument list is empty, dl_first will not return a value.','\n',char(10)),'dl','dl_first list','First element of *dynlist*','dl_last, dl_get, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(316,'dl_concat','command',6,'dl_concat','Concatenate one list onto the end of another','dl_concat takes the elements of the *from* list and appends them to the *to* list.  It''s behavior is similar to dl_combine, except that the origin *from* list is permanently changed to reflect the concatenation.  As it changes the *from, * this can lead to unexpected consequences if care is not taken, making it generally preferable to simply replace the existing list using `dl_local` and `dl_combine.`','dl','dl_concat to from','The *to* list','dl_append, dl_collapse, dl_combine, dl_llist, dl_unpack','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(317,'dl_gamma','command',6,'dl_gamma','Compute values of the gamma distribution','The dl_gamma function calculates the value of the gamma probability distribution defined by the two paramters at particular values of x.','dl','dl_gamma x l r','list of gamma values','dl_gaussian, dl_weibull','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(318,'dl_restructure','command',6,'dl_restructure','Restructure an unstructured list to have the same stucture as another','This function restructures a list of values to be of the same structure as a target list.  A collapsed list can, for instance, be put back into a structured list.','dl','dl_restructure dynlist structure','New list of restructured data','dl_reshape','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(319,'dl_get','command',6,'dl_get','Get a copy of a single element from a list','This function returns a copy of the *n*-th element of the list supplied as a first argument.  Unless *list* is itself a list of lists, the return value of this function will be a Tcl list rather than a dynamic list.  This function will return an error if *n* is not a Tcl numerical list, or if it is too great or too small to index the list.  This function should be avoided within programmes except as a last resort - not only is a loop written in Tcl much slower than the use of an existing dynlist function, but the function is slowed down by the fact that it uses Tcl lists.  It should probably only be used for debugging.','dl','dl_get list index','The *n*-th element from *list*','dl_put, dl_first, dl_last, dl_tcllist','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(320,'dl_sdfs','command',6,'dl_sdfs','Compute spike density functions for lists of spike times','Compute spike density functions for lists of spike times','dl','dl_sdfs list start stop kernel_sd kernel_nsds resolution','','','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(321,'dl_popTemps','command',6,'dl_popTemps','Delete unneeded temporary lists','This function is used for freeing unneeded temporary dynamic lists, thus preventing them from consuming system memory.  It existance is related to the way %%\%%dlsh%%\%% and Tcl handle function return values: many %%\%%dlsh%%\%% functions, when called, return a dynamic list.  In order for Tcl to be able to manipulate these lists, the actual return value is the name of a local list, which can then be passed to other functions, or converted to a global list (with dl_set) or a return list (with dl_return).  If a function manipulates a lot of data, it often happens that temporary lists which are no longer needed accumulate, and consume large chunks of memory.  As a solution to this problem, the dl_popTemps function deletes all temporary lists created since the last call to the dl_pushTemps function.  This should be safe to do at any time, since in principle, a %%\%%dlsh%%\%% script has no way of knowing about temporary lists which still exist after a line of Tcl code has finished executing.  It is recommended to use these two functions at the beginning and end of loops of Tcl code, or as a (possibly better) alternative to insert a call to dl_clean.','dl','dl_popTemps','','dl_pushTemps, dl_clean','beginner',0,'stable',0,'',1,0,'2025-12-03 03:54:56','2025-12-03 03:54:56');
INSERT INTO entries VALUES(322,'dl_zip','command',6,'dl_zip','Zip N same-shape lists into N-tuples at the leaves',replace('This function takes one or more dynlists of identical shape and combines them, leaf-by-leaf, into N-tuples. It is the inverse of separating a list-of-tuples into per-channel lists, and it generalises ``dl_transpose [dl_llist a b ...]`` from 1-D inputs to arbitrarily nested structure.\n\nFor flat input lists of length n, the result is an n-long list of N-tuples (each a length-N sublist). For nested inputs, the outer structure is preserved and the zip happens at the deepest level. All inputs must have identical shape and identical leaf datatype; v1 rejects mismatches rather than truncating.\n\nA common use is packing per-channel vectors (R, G, B; or X, Y, Z) into per-element tuples directly inside any nesting that the upstream pipeline produced — no flatten-then-restructure step required.','\n',char(10)),'dl','dl_zip dynlist ?dynlist ...?','New list of N-tuples at the leaves','dl_transpose, dl_transposeAt, dl_llist, dl_restructure, dl_pack','beginner',0,'stable',0,'',1,0,'2026-05-28 02:32:00','2026-05-28 02:32:00');
INSERT INTO examples VALUES(1,1,'Usage','','See the example for dlp_addErrbarCmd','','text','example','','',0,'2025-12-03 03:54:55');
INSERT INTO examples VALUES(2,2,'Usage','',replace('% dlp_setpanels 6 5 ;# a six by seven grid\n6 5\n% dlp_pushpanel 7 ;# Row 2, Column 3\n% getfviewport\n0.399000 0.664444 0.598500 0.830556\n% dlp_pushpanel 8 ;# Row 2, Column 4 within the first panel\n% getfviewport\n0.518700 0.775185 0.558600 0.802870\n% dlp_pushpanel 3 ;# Row 1, Column 4 within the second panel(!)\n% getfviewport\n0.542640 0.798256 0.550620 0.802870\n% # insert plotting commands here to draw into the panel...\n% dlp_poppanel ;# go back to the second panel setting\n% getfviewport\n0.542640 0.798256 0.550620 0.802870\n% dlp_poppanel ;# and the first (2-3) selected\n% getfviewport\n0.518700 0.775185 0.558600 0.802870\n% dlp_poppanel ;# and finally, put the screen back to where we\n% # found it','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(3,3,'Usage','',replace('% dlp_create myplot\nmyplot\n% dlp_cmd myplot "dl_local as $\backslash$[dlp_getaspect $\backslash$$hisplot$\backslash$]"\nmyplot:precmds\n% dlp_cmd myplot "dlg_lines $\backslash$"1 2 2 1 1$\backslash$" $\backslash$[dl_div $\backslash$"2 2 3 3 2$\backslash$"$\backslash$$s$\backslash$]>    -fillcolor $olors(red)"\nmyplot:precmds\n% dlp_addXData myplot "1 3 5 7"\n0\n% dlp_addYData myplot "9 6 4 0"\n0\n% dlp_draw myplot lines 0\nmyplot:plotcmds\n% dlp_plot myplot\nmyplot\n% clearwin\n% setfviewport .3 .1 .7 .9\n% dlp_plot myplot\nmyplot','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
