INSERT INTO examples VALUES(8,9,'Usage','',replace('% dlp_setpanels 2 3\n2 3\n% dlp_create myplot\nMaypole\n% dl_local xdata [dl_series 0 3.141593 [expr 3.141593/10]]\n&data_0&\n% dlp_addXData myplot $data\n0\n% dlp_addYData myplot [dl_cos $data]\n0\n% dlp_draw myplot lines 0\nmyplot:plotcmds\n% dlp_set myplot title "First Plot"\nmyplot:xtitle\n% dlp_subplot myplot 0\nMaypole\n% dlp_set myplot title "Second Plot"\nmyplot:title\n% dlp_subplot myplot 1\nmyplot\n% dlp_set myplot title "Third Plot"\nmyplot:title\n% dlp_subplot myplot 2\nmyplot\n% dlp_setpanels 2 1\n2 1\n% dlp_set myplot title "Larger Plot"\nmyplot:title\n% dlp_subplot myplot 1\nmyplot','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(9,11,'Usage','',replace('% dlp_create myplot\nmyplot\n% dlp_addXData myplot "1 2 3 4 5"\n0\n% dlp_addYData myplot "1 4 9 16 25"\n0\n% dlp_draw myplot lines 0\nmyplot:plotcmds\n% dlp_postcmd myplot "dl_set xhalf $\backslash$[dl_div $\backslash$[dl_sub $\backslash$$hisplot:cur_xmax>    $\backslash$$hisplot:cur_xmin$\backslash$] 2$\backslash$]"\nmyplot:postcmds\n% dlp_postcmd myplot "dl_set myoffs $\backslash$[dl_interleave $\backslash$[dl_bins>    $\backslash$$hisplot:cur_xmin xhalf 5$\backslash$] $\backslash$[dl_bins $\backslash$$hisplot:cur_xmax xhalf 5$\backslash$]$\backslash$]"\nmyplot:postcmds\n% dlp_postcmd myplot "dl_set yhalf $\backslash$[dl_div $\backslash$[dl_sub $\backslash$$hisplot:cur_ymax>    $\backslash$$hisplot:cur_ymin$\backslash$] 2$\backslash$]"\nmyplot:postcmds\n% dlp_postcmd myplot "dlp_disjointLines $\backslash$$hisplot myoffs $\backslash$[dl_repeat $\backslash$[dl_bins>    $\backslash$$hisplot:cur_ymin yhalf 5$\backslash$] 2$\backslash$]"\nmyplot:postcmds\n% dlp_postcmd myplot "dl_delete myoffs xhalf yhalf"\nmyplot:postcmds\n% dlp_plot myplot\nmyplot','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
