INSERT INTO examples VALUES(64,112,'Usage','',replace('% dg_create g\ng\n% dg_addExistingList g [dl_add [dl_zeros 10] 3] threes\ng:threes\n% dl_tcllist g:threes\n3 3 3 3 3 3 3 3 3 3\n% dg_dumpListNames g\n%<nowiki>\n</nowiki>% Database:   g\n%<nowiki>\n</nowiki>% Col  0:     threes','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(65,113,'Usage','',replace('% dl_set x [dl_ones 4]\nx\n% dg_copyExistingList [dg_create g] x\ng:x\n% dl_tcllist g:x\n1 1 1 1\n% dl_tcllist x\n1 1 1 1\n% dg_addExistingList g x y\ng:y\n% dl_tcllist g:y\n1 1 1 1\n% dl_tcllist x\ndynlist "x" not found','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
