INSERT INTO examples VALUES(79,127,'Usage','',replace('% dl_tcllist [dl_log "0 1 2 3 4 5"]\n-Inf 0.000000 0.693147 1.098612 1.386294 1.609438\n% dl_tcllist [dl_log [dl_llist "6 7 8 9" "10 11 12" 2.718282]]\n{1.791759 1.945910 2.079442 2.197225} {2.302585 2.397895 2.484907} 1.000000','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(80,128,'Usage','',replace('% dl_local a "3 6 7 3 5 -4 3 5 7"\n&_0&\n% dl_median $\n5\n% dl_get [dl_sort $] [dl_tcllist [dl_div [dl_length $] 2]]\n5\n% dl_local b [dl_slist It is an ancient mariner]\n&_1&\n% dl_median $\nancient\n% dl_get [dl_sort $] [dl_tcllist [dl_div [dl_length $] 2]]\nancient\n% dl_tcllist [dl_median [dl_llist "4 5 7" 1 1 "2 6 7 9"]]\n1','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
