INSERT INTO examples VALUES(158,213,'Usage','',replace('% dl_tcllist [dl_randchoose 6 5]\n4 5 1 0 2\n% dl_tcllist [dl_randchoose 7 5]\n5 0 6 4 3\n% dl_tcllist [dl_randchoose 7 "5 2 1"]\n{5 0 6 4 3} {3 1} {0}\n% dl_tcllist [dl_randchoose "7 3 9" "5 2 1"]\n{5 0 6 4 3} {2 1} {8}\n% dl_tcllist [dl_permute "3.23 7.65 4.12 9 8.88" [dl_randchoose 5 3]]\n7.650000 9.000000 8.880000','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
