INSERT INTO examples VALUES(160,215,'Usage','',replace('% dl_tcllist [dl_set a [dl_llist [dl_llist "1 4 2" "2 3 1"] "4 3 2"]]\n{{1 4 2} {2 3 1}} {4 3 2}\n% dl_tcllist [dl_sort a]\n{{1 2 4} {1 2 3}} {2 3 4}\n% dl_set b [dl_llist [dl_slist "Jack" "Josh" "James"] "1 3. 2"]\nb\n% dl_tcllist [dl_sort b]\n{Jack James Josh} {1.000000 2.000000 3.000000}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(161,216,'Usage','',replace('% dl_tcllist [dl_acos [dl_series -1 1 .5]]\n3.141593 2.094395 1.570796 1.047198 0.000000\n% dl_tcllist [dl_acos [dl_series -2 2]]\nNaN 3.141593 1.570796 0.000000 NaN','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(162,217,'Usage','',replace('% dl_tcllist [dl_sortByList "1 2 3 4 5" "0 1 0 0 1"]\n{1 3 4} {2 5}\n% dl_local height "1.73 1.68 1.97 1.83 1.79"\n&eight_0&\n% dl_local gender [dl_slist M F M M F]\n&ender_1&\n% dl_tcllist [dl_sortByList $eight $ender]\n{1.680000 1.790000} {1.730000 1.970000 1.830000}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
