INSERT INTO examples VALUES(166,221,'Usage','',replace('% dl_tcllist [dl_zeros 5]\n0 0 0 0 0\n% dl_tcllist [dl_zeros "4.5 3"]\n{0.000000 0.000000 0.000000 0.000000} {0.000000 0.000000 0.000000}\n% dl_tcllist [dl_zeros [dl_llist "2 1" 2]]\n{{0 0} 0} {{0 0}}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(167,222,'Usage','',replace('% dl_pickone "2 4 5 6 8"\n6\n% dl_pickone "2 4 5 6 8"\n8\n% dl_tcllist [dl_pickone [dl_llist "1 2 3 4 5" "5 4 3 2 1" "2 1 4 3 5">	"4 5 3 4 2"]]\n2 1 4 3 5','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(168,224,'Usage','',replace('% dl_local name [dl_slist Louis Napoleon Bonaparte]\n&ame_0&\n% dl_tcllist [dl_sortByLists $ame {1 1 2}]\n{Louis Napoleon} Bonaparte\n% dl_tcllist [dl_sortByLists $ame {1 1 2} {1 2 1}]\nLouis Bonaparte Napoleon {}\n# Call the dl_uniqueCross function to relate the result to our table\n% dl_tcllist [dl_uniqueCross {1 1 2} {1 2 1}]\n{1 2 1 2} {1 1 2 2}\n# The elements in our returned list were the entries {1 1}, {2 1},\n#   {1 2} and {2 2} in the table\n% dl_tcllist [dl_sortByLists $ame {1 1 2} {1 2 1} {2 1 1}]\n{} Bonaparte Napoleon {} Louis {} {} {}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(169,225,'Usage','',replace('% dl_return [dl_series 0 5]>0<% dl_tcllist>0<0 1 2 3 4 5\n% proc identity { l } { return [dl_return $] }\n% identity [dl_acos 0]>1<% dl_tcllist [identity [dl_acos 0]]\n1.570796','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(170,226,'Usage','',replace('% dl_local a [dl_ilist 1 2 3 4]\n&0&\n% dl_local b [dl_pack $a]\n&_1&\n% dl_tcllist $b\n1 2 3 4\n% dl_dump $a\n1\n2\n3\n4\n% dl_dump $b\nList(3,1)\nList(3,1)\nList(3,1)\nList(3,1)\nList(3,1)','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
