INSERT INTO examples VALUES(172,228,'Usage','',replace('% dl_last "2 7 5"\n5\n% dl_last [dl_slist "Abara" "Cadabra"]\nCadabra\n% dl_last [dl_llist "2 4 5" "6 4 2"]\n%list5%\n% dl_tcllist [dl_last [dl_llist "2 4 5" "6 4 2"]]\n6 4 2','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(173,229,'Usage','',replace('a\n% dl_dir\n{a long 3 3}\n% dl_local Trains [dl_slist "Thomas" "Gordon" "Henry" "James"]\n&rains_0&\n% dl_dir\n{&rains_0& string 4 15} {a long 3 3}\n% dl_tcllist [dl_sort [dl_llist $rains "1 5 3" [dl_llist "2 1" "5 4 5"]]]\n{Gordon Henry James Thomas} {1 32 54} {{1 2} {4 5 5}}\n% dl_dir\n{%list2% long 3 3} {a long 3 3} {%list4% long 3 3} {%list1% long 2 2} {%list3% list 3 15} {%list5% list 3 3} {&rains_0& string 4 15} {%list0% list 2 15}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(174,231,'Usage','',replace('% dl_set a [dl_series 0 9]\na\n% dl_set b [dl_replicate [dl_slist male female] 5]\nb\n% dl_set c "3 4 3 3 2 3 5 4 2 3"\nc\n% dl_tcllist [dl_sortByLists a b c]\n{} {4 8} {3 5 9} {0 2} {1 7} {} {} 6\n% dl_dumpMatrixInCols [dl_sortedFunc a {b c}]\nfemale  2       0.000000\nmale    2       6.000000\nfemale  3       5.666667\nmale    3       1.000000\nfemale  4       4.000000\nmale    4       0.000000\nfemale  5       0.000000\nmale    5       6.000000\n% dl_dumpMatrixInCols [dl_sortedFunc a {b c} dl_stds]\nfemale  2       0.000000\nmale    2       2.828427\nfemale  3       3.055050\nmale    3       1.414214\nfemale  4       4.242640\nmale    4       0.000000\nfemale  5       0.000000\nmale    5       0.000000','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(175,232,'Usage','',replace('% dl_set a [dl_series 0 9]\na\n% dl_set b [dl_replicate [dl_ilist 0 1] 5]\nb\n% dl_set c [dl_repeat [dl_ilist 0 1] 5]\nc\n% dl_tcllist [dl_uniqueCross b c]\n{0 1 0 1} {0 0 1 1}\n% dl_tcllist [dl_sortByLists a b c]\n{0 2 4} {1 3} {6 8} {5 7 9}\n% dl_set d [dl_ilist 0]\nd\n% dl_set e [dl_ilist 0 1]\ne\n% dl_tcllist [dl_sortBySelected a {b c} {d e}]\n{0 2 4} {6 8}\n% dl_tcllist [dl_sortBySelected a {b c} {e d}]\n{0 2 4} {1 3}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
