INSERT INTO examples VALUES(234,295,'Usage','',replace('% dl_tcllist [dl_hist "1 2 3 4 5" 1 6 5]\n1 1 1 1 1\n% dl_tcllist [dl_hist "1 2 3 4 5" 1 5 5]\n1 1 1 1 0\n% dl_tcllist [dl_hist "1 2 3 4 5" 5 1 5]\n0 0 0 0 0\n% dl_tcllist [dl_hist [dl_llist [dl_llist "1 2" "3 2 1"] "1 3 8"] 1 6 5]\n3 2 2 0 0','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(235,296,'Usage','',replace('% dl_tcllist [dl_increment "1 2 3 4"]\n1 2 3 4 5\n% dl_tcllist [dl_incr "4 3 2 1"]\n4 3 2 1 2\n% dl_tcllist [dl_increment [dl_create char 2 66 255]]\n2 66 255 0\n% dl_local x [dl_zeros 5]\n&_1&\n% dl_tcllist [dl_incr $ 3]\n0 0 0 1 0','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(236,297,'Usage','',replace('% dl_set a [dl_series 0 9]\na\n% dl_set b [dl_replicate [dl_slist male female] 5]\nb\n% dl_set c "3 4 3 3 2 3 5 4 2 3"\nc\n% dl_set d [dl_slist "male"]\nd\n% dl_set e "3 5"\ne\n% dl_tcllist [dl_sortBySelected a {b c} {d e}]\n{0 2} 6\n% dl_dumpMatrixInCols [dl_selectSortedFunc a {b c} {d e}]\nmale    3       1.000000\nmale    5       6.000000\n% dl_dumpMatrixInCols [dl_selectSortedFunc a {b c} {d e} dl_stds]\nmale    3       1.414214\nmale    5       0.000000','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(237,298,'Usage','',replace('% dl_tcllist [dl_filedir [dl_slist /usr/local/bin/dlwish \> /home/norbert/e5234.jpg]]\n/usr/local/bin /home/norbert','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(238,299,'Usage','',replace('% dl_local a [dl_llist [dl_llist "3 4 5" "4 5 6" "4 5 7 8"] "4 5 6" 3 4]\n&_0\&\n% dl_dumpMatrixInCols $\nList(3,3)       4       3       4\nList(3,3)       5          *       *   \nList(3,4)       6          *       *','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(239,300,'Usage','',replace('% dl_local a [dl_llist "3 4 3" "2 3" [dl_llist "4 3"]]\n&_0&\n% dl_tcllist [dl_counts $ 2 5]\n3 2 2','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(240,301,'Usage','',replace('% dl_dumpMatrix [dl_llist [dl_llist "3 4 5" "4 5 6" "4 5 7 8"] "4 5 6" 3 4]\nList(3,3)       List(3,3)       List(3,4)\n4       5       6\n3\n4\n% dl_dumpMatrix [dl_llist [dl_slist Bordeau Bourgogne Beauce] "2 3 4"]\nBordeau Bourgogne       Beauce\n2       3       4\n% dl_dumpMatrix "4 5 6"\ndl_dumpMatrix: invalid dynlist','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(241,302,'Usage','',replace('% dl_tcllist [dl_cycle [dl_series 0 5] 0]\n0 1 2 3 4 5\n% dl_tcllist [dl_cycle [dl_series 0 5] 2]\n4 5 0 1 2 3\n% dl_tcllist [dl_cycle [dl_series 0 5] -2]\n2 3 4 5 0 1','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(242,303,'Usage','',replace('% dl_tcllist [dl_ceil [dl_flist 1 2.019 3.7]]\n1 3 4','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(243,304,'Usage','',replace('% dl_tcllist [dl_transposeAt [dl_llist 1 2 3 4] 0]\n{1 2 3 4}\n% dl_tcllist [dl_transpose [dl_llist "1 2" "2 3" "3 6" "4 5"] 0]\n{1 2 3 4} {2 3 6 5}\n% dl_local a [dl_llist "2 3 4" "3 4 5"]\n&a_0&\ndl_local b [dl_llist $a [dl_add $a 1] [dl_add $a 2]]\n&b_1&\n% dl_tcllist $b\n{{2 3 4} {4 5 6}} {{3 4 5} {5 6 7}} {{4 5 6} {6 7 8}}\n% dl_tcllist [dl_transposeAt $b 0]\n{{2 3 4} {3 4 5} {4 5 6}} {{4 5 6} {5 6 7} {6 7 8}}\n% dl_tcllist [dl_transposeAt $b 1]\n{{2 4} {3 5} {4 6}} {{3 5} {4 6} {5 7}} {{4 6} {5 7} {6 8}}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(244,305,'Usage','',replace('% dl_tcllist [dl_cumprod "1 3 5 4 2"]\n1 3 15 60 120\n% dl_tcllist [dl_local factorials [dl_cumprod "1 2 3 4 5 6"]]\n1 2 6 24 120 720','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(245,306,'Usage','',replace('% dl_tcllist [dl_sortIndices [dl_slist Lord of the Flies]]\n3 0 1 2\n% dl_tcllist [dl_sortIndices [dl_llist "3 1 2" "4 5 4" "7 6 5"]]\n{1 2 0} {0 2 1} {2 1 0}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(246,307,'Usage','',replace('% dl_set a [dl_llist "2 3 4" [dl_llist "4 5 6" "4 3 2"]]\na\n% dl_set b [dl_bmeans a]\nb\n% dl_tcllist b\n3.000000 {5.000000 3.000000}\n% dl_delete a b','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(247,308,'Usage','',replace('% dl_local a [dl_llist "2 3 4" "3 4 5" "4 5 6"]\n&_0&\n% dl_tcllist [dl_means [dl_llist $ $]]\n{3.000000 4.000000 5.000000} {3.000000 4.000000 5.000000}\n% dl_local b [dl_llist [dl_llist "2 3" "4 2"] [dl_llist "5 4" "1 2"]]\n&_1&\n% dl_tcllist [dl_means [dl_llist $]]\n{{3.500000 3.500000} {2.500000 2.000000}}\n% dl_tcllist [dl_means [dl_llist [dl_llist $]]]\n{{{2.000000 3.000000} {4.000000 2.000000}} {{5.000000 4.000000} {1.000000 2.0000\n00}}}\n% dl_tcllist [dl_div $ [dl_means [dl_llist $]]]\n{{0.571429 0.857143} {1.600000 1.000000}} {{1.428571 1.142857} {0.400000 1.00000\n0}}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(248,309,'Usage','',replace('% dl_tcllist [dl_cosh [dl_flist 0 1 $e $pi]]\n1.000000 1.543081 7.610125 11.591954','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(249,310,'Usage','',replace('% dl_tcllist [dl_sub 2 1]\n1\n% dl_tcllist [dl_sub [dl_llist "2 3 4" "1 2 3"] 2]\n{0 1 2} {-1 0 1}\n% dl_tcllist [dl_sub [dl_llist "2 3 4" "1 2 3"] [dl_llist "1 3 2" 2]]\n{1 0 2} {-1 0 1}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(250,311,'Usage','',replace('% dl_dump [dl_series 2 4]\n2\n3\n4\n% set $name [open [dl_tempname] "RDWR CREAT EXCL"]\nfile3\n% dl_dump [dl_llist "3 4 5" "4 5 6"] $name\n% close $name\n% exec cat tempfile.txt\nList(3,3)\nList(3,3)','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(251,312,'Usage','',replace('% dl_tcllist [dl_diff "1 2 4"]\n1 2\n% dl_tcllist [dl_diff "2 7 5 4" 2]\n3 -3\n% dl_tcllist [dl_diff "1 5 6" 3]\n% dl_tcllist [dl_diff [dl_llist "2 5 4" "3 5" "4 5 3 2"] 2]\n2 {} {-1 -3}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(252,313,'Usage','',replace('% dl_critf 0.05 4 12\n3.259167\n% dl_tcllist [dl_critf 0.05 4 [dl_fromto 10 15]]\n3.478050 3.356690 3.259167 3.179117 3.112250\n% dl_tcllist [dl_critf "0.25 0.10 0.05 0.01" 4 12]\n1.550351 2.480102 3.259167 5.411952','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
