INSERT INTO examples VALUES(254,315,'Usage','',replace('% dl_first "2 3 55"\n2\n% dl_tcllist [dl_first [dl_llist "2 3 55"]]\n2 3 55\n% dl_first [dl_slist "Arthur" "Ford" "Trillian"]\nArthur\n% dl_tcllist [dl_first [dl_slist "Arthur" "Ford" "Trillian"]]\ndynlist "Arthur" not found','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(255,316,'Usage','',replace('% dl_set a [dl_fromto 0 4]\na\n% dl_tcllist a\n0 1 2 3\n% dl_set b [dl_fromto 5 9]\nb\n% dl_tcllist [dl_concat a b]\n0 1 2 3 5 6 7 8\n% dl_tcllist a\n0 1 2 3 5 6 7 8','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(256,317,'Usage','',replace('% dl_tcllist [dl_gamma 5 .5 1]\n0.041042\n% dl_tcllist [dl_gamma 9 .5 5]\n0.094904','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(257,318,'Group flat triplets into a per-trial template','Build a template that has the desired nesting (here: n_obs sublists, each of length nlayers), then restructure a flat list of n_obs*nlayers triplets to match it.',replace('% set n_obs 3\n3\n% set nlayers 2\n2\n% dl_local triplets [dl_llist "1 1 1" "2 2 2" "3 3 3" "4 4 4" "5 5 5" "6 6 6"]\n% dl_local shape    [dl_repeat [dl_llist [dl_ones $nlayers]] $n_obs]\n% dl_tcllist [dl_restructure $triplets $shape]\n{{1 1 1} {2 2 2}} {{3 3 3} {4 4 4}} {{5 5 5} {6 6 6}}','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(258,319,'Usage','',replace('% dl_get "1 2 3" 1\n2\n% dl_local a [dl_slist "Gottlieb" "Babette" "Sepp"]\n&_0&\n% dl_get $ 2\nSepp\n% dl_get $ 3\ndl_get: index out of range\n% dl_tcllist [dl_get [dl_llist "3 2 5" "6 5 4" "42"] 2]\n42\n% dl_get [dl_llist "3 2 5" "6 5 4" "42"] 2\n%list11%','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(259,321,'Usage','',replace('%list0%\n% dl_pushTemps\n% dl_ilist 3 5 6\n%list1%\n% dl_slist William\n%list2%\n% dl_dir\n{%list2% string 1 15} {%list0% list 0 15} {%list1% long 3 15}\n% dl_popTemps\n% dl_dir\n{%list0% list 0 15}\n% dl_popTemps\ndl_popTemps: popped empty templist stack','\n',char(10)),'','text','example','','',0,'2025-12-03 03:54:56');
INSERT INTO examples VALUES(260,322,'Flat lists','Two or three flat lists become a list of pairs / triplets.',replace('% dl_tcllist [dl_zip [dl_fromto 0 3] [dl_fromto 10 13]]\n{0 10} {1 11} {2 12}\n% dl_tcllist [dl_zip {1 2 3} {4 5 6} {7 8 9}]\n{1 4 7} {2 5 8} {3 6 9}','\n',char(10)),'','text','example','','',0,'2026-05-28 02:32:00');
INSERT INTO examples VALUES(261,322,'Nested lists','Outer structure is preserved; the zip happens at the leaves.',replace('% dl_tcllist [dl_zip [dl_llist "1 2" "3 4"] [dl_llist "5 6" "7 8"]]\n{{1 5} {2 6}} {{3 7} {4 8}}','\n',char(10)),'','text','example','','',1,'2026-05-28 02:32:00');
INSERT INTO examples VALUES(262,322,'Packing per-channel RGB','Generate H, S, V each in an n_obs × nlayers shape, convert to R, G, B vectorized, then zip the three channels into per-leaf {r g b} triplets — no dl_restructure needed.',replace('# inside an ess loader (n_obs × nlayers structure throughout)\ndl_local shape [dl_repeat $nlayers $n_obs]\ndl_local h6 [dl_mult 6.0 [dl_urand $shape]]\ndl_local s  [dl_add 0.6 [dl_mult 0.4 [dl_urand $shape]]]\ndl_local v  [dl_add 0.5 [dl_mult 0.5 [dl_urand $shape]]]\n# ... vectorized HSV→RGB yields r, gn, b each shaped n_obs × nlayers ...\ndl_set $g:layer_rgb [dl_zip $r $gn $b]\n# $g:layer_rgb is now n_obs × nlayers × 3','\n',char(10)),'','text','example','','',2,'2026-05-28 02:32:00');
